INSERT INTO `custom_pages_i18n` VALUES ('11111111-2222-3333-4444-555555555571','11111111-2222-3333-4444-555555555574','tr','Kalite Belgelerimiz & Kalite Standartlarımız','kalite-belgelerimiz-kalite-standartlarimiz','{\"html\": \"\"}','Ensotek kalite belgeleri ve sertifikaları sayfası','Ensotek kalite belgeleri – sertifikalar','Kalite Belgelerimiz & Kalite Standartlarımız | Ensotek','Ensotek kalite belgeleri ve kalite standartları: ISO 9001, ISO 14001, iş sağlığı ve güvenliği yaklaşımı ve uygunluk dokümantasyonları. Sertifikaları ayrı görsellerle inceleyin.','ensotek,kalite,sertifika,iso 9001,iso 14001,iso 45001,ohsas,standartlar','2026-03-23 04:11:28.796','2026-03-23 04:11:28.796'),('11111111-2222-3333-4444-555555555572','11111111-2222-3333-4444-555555555574','en','Quality Certificates & Quality Standards','quality-certificates-quality-standards','{\"html\": \"\"}','Ensotek quality certificates and standards page','Ensotek quality certificates – certifications','Quality Certificates & Quality Standards | Ensotek','Ensotek quality certificates and standards: ISO 9001, ISO 14001, occupational health & safety approach and compliance documentation. Review certificates as individual visuals.','ensotek,quality,certificate,iso 9001,iso 14001,iso 45001,ohsas,standards','2026-03-23 04:11:28.796','2026-03-23 04:11:28.796'),('11111111-2222-3333-4444-555555555573','11111111-2222-3333-4444-555555555574','de','Qualitätszertifikate & Qualitätsstandards','qualitaetszertifikate-qualitaetsstandards','{\"html\": \"\"}','Ensotek Qualitätszertifikate und Qualitätsstandards','Ensotek Qualitätszertifikate – Zertifizierungen','Qualitätszertifikate & Qualitätsstandards | Ensotek','Ensotek Qualitätszertifikate und Standards: ISO 9001, ISO 14001, Arbeitsschutz-Ansatz sowie Konformitäts- und Dokumentationsprozesse. Zertifikate als einzelne Visuals prüfen.','ensotek,qualität,zertifikat,iso 9001,iso 14001,iso 45001,ohsas,standards','2026-03-23 04:11:28.796','2026-03-23 04:11:28.796'),('4d3c0d53-de5a-452d-a45b-a14048041fc7','4dda2043-018e-4bf9-b43d-bb5e9de184b9','tr','fdggfdgfdgfdg','fdggfdgfdgfdg','{\"html\":\"gfdgfdgfdgfdg\"}','fdgfdgfdg',NULL,NULL,NULL,NULL,'2026-03-25 04:09:29.398','2026-03-25 04:10:30.155'),('5dd64fc4-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555573','tr','Ensotek Su Soğutma Kuleleri','ensotek-su-sogutma-kuleleri','{\"html\": \"<p>Ensotek, 40 yıllık deneyimiyle İstanbul Merkez Ofis ve Ankara Fabrikası\'nda uzman kadrosu ile su soğutma kuleleri alanında hizmet vermektedir. Firmamız, Türkiye\'nin en büyük su soğutma kulesi üretim tesisine sahiptir.</p><p>Cam elyaf takviyeli polyester (FRP) malzemeden, korozyona dayanıklı, boyasız, uzun ömürlü, bakımı kolay ve düşük yatırım/işletme maliyetli açık ve kapalı devre su soğutma kuleleri üretmekteyiz.</p><p>Hem yurt içinde hem de yurt dışında binlerce projede başarılı çözümler ürettik. En iyi reklamın ürünün kendisi olduğu prensibiyle, müşterilerimizin tekrar tekrar bizi tercih etmesini ve her seferinde memnun kalmasını hedefliyoruz.</p><p>Ar-Ge faaliyetlerimiz ve müşteri geri bildirimleriyle ürünlerimizi sürekli geliştiriyor, Türkiye içinde ve dışında örnek bir firma konumunda yer alıyoruz. Ensotek, CTI (Cooling Technology Institute) ve SOSIAD üyesidir; üretim sistemimiz ISO-9001:2015 ile belgelenmiştir ve ürünlerimiz CE belgelidir.</p>\"}','Ensotek’in 40 yıllık deneyimi, FRP su soğutma kuleleri üretimi ve ulusal/uluslararası projelerdeki lider konumu özetlenir.','Ensotek su soğutma kuleleri üretim tesisi','Ensotek Su Soğutma Kuleleri | 40 Yıllık Deneyim','Ensotek, 40 yıllık deneyimi ve Türkiye’nin en büyük su soğutma kulesi üretim tesisiyle FRP açık ve kapalı devre soğutma kuleleri sunan sektör lideridir.','ensotek,hakkimizda,frp,su sogutma kuleleri,uretim tesisi,acik devre,kapali devre','2026-03-23 04:11:28.777','2026-03-23 04:11:28.777'),('5dd65317-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555573','en','Ensotek Water Cooling Towers','ensotek-water-cooling-towers','{\"html\": \"<p>Ensotek serves its customers from its Istanbul Headquarters and Ankara Factory with an expert team and over 40 years of experience in water cooling towers. Our company owns the largest water cooling tower production facility in Turkey.</p><p>Ensotek manufactures open and closed circuit water cooling towers made from Fiberglass Reinforced Polyester (FRP), which are corrosion resistant, long-lasting, easy to maintain and offer low investment and operating costs.</p><p>We have delivered successful solutions in thousands of projects both in Turkey and abroad. With the principle that the best advertisement is the product itself, we aim for our customers to work with us repeatedly and be satisfied every time.</p><p>Through continuous R&amp;D activities and customer feedback, we keep improving our products and have become an exemplary company in Turkey and worldwide. Ensotek is a member of CTI (Cooling Technology Institute) and SOSIAD; our production system is certified with ISO-9001:2015 and our products are CE marked.</p>\"}','Summarizes Ensotek’s 40+ years of experience, FRP water cooling tower manufacturing, and leadership in domestic/international projects.','Ensotek water cooling tower production facility','Ensotek Water Cooling Towers | 40+ Years of Experience','Ensotek is the sector leader with Turkey’s largest water cooling tower production facility, delivering FRP open and closed circuit cooling towers for projects worldwide.','ensotek,about us,frp,water cooling towers,production facility,open circuit,closed circuit','2026-03-23 04:11:28.777','2026-03-23 04:11:28.777'),('5dd65576-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555573','de','Ensotek Wasserkühltürme','ensotek-wasserkuehltuerme','{\"html\": \"<p>Ensotek betreut seine Kunden mit über 40 Jahren Erfahrung und einem erfahrenen Expertenteam vom Hauptsitz in Istanbul sowie dem Werk in Ankara im Bereich Wasserkühltürme. Unser Unternehmen verfügt über die größte Produktionsanlage für Wasserkühltürme in der Türkei.</p><p>Wir fertigen offene und geschlossene Wasserkühltürme aus glasfaserverstärktem Polyester (GFK/FRP) – korrosionsbeständig, unlackiert, langlebig, wartungsfreundlich und mit niedrigen Investitions- und Betriebskosten.</p><p>Wir haben in der Türkei und im Ausland in tausenden Projekten erfolgreiche Lösungen umgesetzt. Nach dem Prinzip, dass das beste Marketing das Produkt selbst ist, möchten wir, dass unsere Kunden uns immer wieder wählen und jedes Mal zufrieden sind.</p><p>Durch kontinuierliche F&amp;E-Aktivitäten und Kundenfeedback verbessern wir unsere Produkte fortlaufend und zählen zu den beispielgebenden Unternehmen in der Türkei und international. Ensotek ist Mitglied des CTI (Cooling Technology Institute) und der SOSIAD; unser Produktionssystem ist nach ISO-9001:2015 zertifiziert und unsere Produkte sind CE-gekennzeichnet.</p>\"}','Zusammenfassung von Ensoteks über 40 Jahren Erfahrung, der FRP/GFK-Produktion und der führenden Rolle in nationalen und internationalen Projekten.','Produktionsanlage für Ensotek Wasserkühltürme','Ensotek Wasserkühltürme | Über 40 Jahre Erfahrung','Ensotek ist Branchenführer mit der größten Produktionsanlage für Wasserkühltürme in der Türkei und liefert FRP/GFK-Kühlturm-Lösungen für Projekte weltweit.','ensotek,über uns,gfk,frp,wasserkühltürme,produktionsanlage,offener kreislauf,geschlossener kreislauf','2026-03-23 04:11:28.777','2026-03-23 04:11:28.777'),('5dd74a3c-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555571','tr','Misyonumuz','misyonumuz','{\"html\": \"<p>Sektördeki yenilikleri ve gelişmeleri yakından takip ederek, müşterilerimizin beklentilerine ve ihtiyaçlarına en uygun, verimli ve ekonomik çözümleri sunmayı amaçlıyoruz.</p><p>Hem Türkiye\'de hem de dünyada, su soğutma kuleleri denince akla gelen lider firmalardan biri olmayı hedefliyoruz.</p>\"}','Ensotek\'in sektörde yenilikçi, verimli ve ekonomik su soğutma kuleleri çözümleri sunma hedefini tanımlar.','Misyonumuz - Ensotek Su Soğutma Kuleleri','Misyonumuz | Ensotek Su Soğutma Kuleleri','Sektördeki yenilikleri takip ederek su soğutma kulelerinde en iyi çözümleri sunmayı hedefleyen Ensotek\'in misyonu.','ensotek,misyon,su sogutma kuleleri,frp','2026-03-23 04:11:28.784','2026-03-23 04:11:28.784'),('5dd74ddb-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555571','en','Our Mission','our-mission','{\"html\": \"<p>Our mission is to closely follow innovations and developments in the sector, providing our customers with efficient and economical solutions that best suit their needs and expectations.</p><p>We aim to be one of the leading companies in Turkey and worldwide when it comes to water cooling towers.</p>\"}','Describes Ensotek\'s mission to provide efficient and economical water cooling tower solutions worldwide.','Our Mission - Ensotek Water Cooling Towers','Our Mission | Ensotek Water Cooling Towers','Ensotek\'s mission is to follow innovations and provide efficient, economical water cooling tower solutions tailored to customer needs.','ensotek,mission,water cooling towers,frp','2026-03-23 04:11:28.784','2026-03-23 04:11:28.784'),('5dd74fca-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555571','de','Unsere Mission','unsere-mission','{\"html\": \"<p>Unsere Mission ist es, Innovationen und Entwicklungen in der Branche kontinuierlich zu verfolgen und unseren Kunden effiziente sowie wirtschaftliche Lösungen anzubieten, die bestmöglich zu ihren Erwartungen und Anforderungen passen.</p><p>Wir möchten in der Türkei und international zu den führenden Unternehmen gehören, wenn es um Wasserkühltürme geht.</p>\"}','Beschreibt Ensoteks Mission, effiziente und wirtschaftliche Wasserkühlturm-Lösungen anzubieten und zu den führenden Anbietern zu zählen.','Unsere Mission – Ensotek Wasserkühltürme','Unsere Mission | Ensotek Wasserkühltürme','Ensoteks Mission: Innovationen verfolgen und kundenorientierte, effiziente sowie wirtschaftliche Wasserkühlturm-Lösungen bereitstellen.','ensotek,mission,wasserkühltürme,frp','2026-03-23 04:11:28.784','2026-03-23 04:11:28.784'),('5dd81dd0-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555572','tr','Vizyonumuz','vizyonumuz','{\"html\": \"<p>Vizyonumuz; müşteri memnuniyetini merkeze alarak, kaliteli, verimli ve sürdürülebilir çözümler sunmak; ulusal ve uluslararası pazarda tercih edilen, güvenilir ve öncü bir marka olmaktır.</p>\"}','Ensotek vizyonu: sürdürülebilir kalite ve güvenilir marka yaklaşımı.',NULL,'Vizyonumuz | Ensotek','Müşteri memnuniyetini merkeze alan, sürdürülebilir kalite anlayışıyla hareket eden Ensotek vizyonu.','ensotek,vizyon,surdurulebilir,kalite','2026-03-23 04:11:28.789','2026-03-23 04:11:28.789'),('5dd8203a-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555572','en','Our Vision','our-vision','{\"html\": \"<p>Our vision is to prioritize customer satisfaction by delivering high-quality, efficient and sustainable solutions; and to become a trusted and leading brand in national and international markets.</p>\"}','Ensotek vision: sustainable quality and trusted brand approach.',NULL,'Our Vision | Ensotek','Ensotek’s vision: customer-first approach with sustainable quality and leadership.','ensotek,vision,sustainable,quality','2026-03-23 04:11:28.789','2026-03-23 04:11:28.789'),('5dd82148-266e-11f1-8a30-dc46281c36a8','11111111-2222-3333-4444-555555555572','de','Unsere Vision','unsere-vision','{\"html\": \"<p>Unsere Vision ist es, die Kundenzufriedenheit in den Mittelpunkt zu stellen, hochwertige, effiziente und nachhaltige Lösungen zu liefern und eine bevorzugte, verlässliche und führende Marke auf nationalen und internationalen Märkten zu werden.</p>\"}','Ensotek Vision: nachhaltige Qualität und verlässlicher Markenansatz.',NULL,'Unsere Vision | Ensotek','Ensoteks Vision: kundenorientiert, nachhaltig und führend – mit Fokus auf Qualität.','ensotek,vision,nachhaltig,qualität','2026-03-23 04:11:28.789','2026-03-23 04:11:28.789'),('5dda105a-266e-11f1-8a30-dc46281c36a8','55550002-5555-4555-8555-555555550002','tr','Gizlilik Politikası','gizlilik-politikasi','{\"html\": \"<section class=\\\"container mx-auto px-4 py-10\\\"><h1 class=\\\"text-3xl md:text-4xl font-semibold text-slate-900 mb-4\\\">Gizlilik Politikası</h1><p class=\\\"text-slate-700 mb-8\\\">Ensotek olarak, web sitemizi ziyaret eden kullanıcılarımızın gizliliğini korumayı ve kişisel verileri yürürlükteki mevzuata uygun şekilde işlemeyi taahhüt ederiz. Bu metin; hangi verileri topladığımızı, ne amaçla işlediğimizi, nasıl sakladığımızı ve haklarınızı açıklar.</p><div class=\\\"grid md:grid-cols-2 gap-6 mb-10\\\"><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">1. Kapsam</h2><p class=\\\"text-slate-700\\\">Bu politika; web sitesi ziyaretleri, iletişim formları, teklif/ürün talepleri, e-posta iletişimi ve teknik loglar dahil olmak üzere dijital kanallardan elde edilen verileri kapsar.</p></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">2. Toplanan Veriler</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>İletişim: ad-soyad, e-posta, telefon, firma/ünvan (varsa)</li><li>Talep içeriği: mesaj, teknik ihtiyaçlar, ürün ilgisi</li><li>Teknik: IP, tarayıcı/cihaz, sayfa görüntüleme, erişim zamanı, log kayıtları</li><li>Çerezler: tercih ve kullanım verileri (detaylar Çerez Politikası’nda)</li></ul></div></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">3. İşleme Amaçları</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Taleplerinize yanıt vermek, teklif süreçlerini yürütmek ve iletişimi sürdürmek</li><li>Web sitesi güvenliği, hata analizi, performans ve kullanıcı deneyimini iyileştirmek</li><li>Yasal yükümlülüklerin yerine getirilmesi ve uyuşmazlıkların yönetilmesi</li><li>İş sürekliliği ve bilgi güvenliği süreçlerinin yürütülmesi</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">4. Saklama Süreleri</h2><p class=\\\"text-slate-700 mb-3\\\">Veriler; ilgili amacın gerektirdiği süre boyunca ve/veya mevzuatta öngörülen sürelerle sınırlı olacak şekilde saklanır.</p><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>İletişim/talep kayıtları: süreç gereksinimi + yasal süreler</li><li>Güvenlik ve sistem logları: güvenlik/denetim ihtiyacı ile sınırlı</li><li>Çerez verileri: çerez türüne göre değişir</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">5. Üçüncü Taraflar ve Aktarımlar</h2><p class=\\\"text-slate-700 mb-3\\\">Hizmet altyapısı (barındırma, e-posta gönderimi, güvenlik, analiz vb.) kapsamında sınırlı ölçüde hizmet sağlayıcılarla paylaşım olabilir. Bu paylaşımlar, sözleşmesel yükümlülükler ve teknik/idari tedbirlerle yönetilir.</p><p class=\\\"text-slate-700\\\">Üçüncü tarafların veri işleme faaliyetleri, kendi politikalarına tabi olabilir. Bu nedenle ilgili sağlayıcıların koşullarını incelemenizi öneririz.</p></div><div class=\\\"bg-gradient-to-br from-slate-50 to-blue-50 border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">6. Güvenlik Önlemleri</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Erişim kontrolü ve yetkilendirme</li><li>İletişim güvenliği ve izleme</li><li>Yedekleme ve iş sürekliliği tedbirleri</li><li>Loglama ve olay yönetimi süreçleri</li></ul></div><div class=\\\"bg-slate-900 text-white rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold mb-3\\\">7. Haklarınız ve İletişim</h2><p class=\\\"text-white/90 mb-3\\\">Kişisel verilerinizle ilgili talepleriniz için bizimle iletişime geçebilirsiniz. Başvurular, ilgili mevzuat kapsamındaki haklar çerçevesinde değerlendirilir.</p><p class=\\\"text-white/80\\\">Ayrıca KVKK/aydınlatma metinlerimiz ve çerez tercihleri sayfası üzerinden detaylı bilgilere ulaşabilirsiniz.</p></div></section>\"}','Ensotek Gizlilik Politikası: web sitesinde toplanan veriler, kullanım amaçları, saklama, güvenlik ve kullanıcı hakları hakkında bilgilendirme.','Ensotek Gizlilik Politikası sayfası','Gizlilik Politikası | Ensotek','Ensotek Gizlilik Politikası; toplanan veriler, işleme amaçları, saklama ve güvenlik önlemleri ile kullanıcı hakları hakkında bilgilendirir.','ensotek,kurumsal,gizlilik politikası,veri güvenliği,kvkk,çerezler','2026-03-23 04:11:28.802','2026-03-23 04:11:28.802'),('5dda162b-266e-11f1-8a30-dc46281c36a8','55550002-5555-4555-8555-555555550002','en','Privacy Policy','privacy-policy','{\"html\": \"<section class=\\\"container mx-auto px-4 py-10\\\"><h1 class=\\\"text-3xl md:text-4xl font-semibold text-slate-900 mb-4\\\">Privacy Policy</h1><p class=\\\"text-slate-700 mb-8\\\">At Ensotek, we are committed to protecting the privacy of visitors and processing personal data in compliance with applicable laws. This notice explains what we collect, why we process it, how we store it, and your rights.</p><div class=\\\"grid md:grid-cols-2 gap-6 mb-10\\\"><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">1. Scope</h2><p class=\\\"text-slate-700\\\">This policy covers data collected via website visits, contact forms, quote/product requests, email communications, and technical logs.</p></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">2. Information We Collect</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Contact details: name, email, phone, company/title (if provided)</li><li>Request content: message, technical needs, product interest</li><li>Technical data: IP, browser/device, page views, access times, logs</li><li>Cookies: usage and preference data (see Cookie Policy)</li></ul></div></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">3. Purposes of Processing</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>To respond to inquiries, manage quotation processes, and maintain communication</li><li>To improve website security, error analysis, performance and user experience</li><li>To comply with legal obligations and manage disputes</li><li>To operate business continuity and information security processes</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">4. Retention</h2><p class=\\\"text-slate-700 mb-3\\\">We retain data only as long as necessary for the stated purposes and/or as required by law.</p><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Contact/request records: as needed for the process and legal requirements</li><li>Security/system logs: limited to security/audit needs</li><li>Cookie data: varies by cookie type</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">5. Service Providers and Sharing</h2><p class=\\\"text-slate-700 mb-3\\\">We may share limited data with service providers (hosting, email delivery, security, analytics, etc.) under contractual and security safeguards.</p><p class=\\\"text-slate-700\\\">Third-party processing may be subject to their own policies. We recommend reviewing relevant provider terms.</p></div><div class=\\\"bg-gradient-to-br from-slate-50 to-blue-50 border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">6. Security Measures</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Access controls and authorisation</li><li>Secure communications and monitoring</li><li>Backups and business continuity</li><li>Logging and incident management processes</li></ul></div><div class=\\\"bg-slate-900 text-white rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold mb-3\\\">7. Your Rights and Contact</h2><p class=\\\"text-white/90 mb-3\\\">You may contact us regarding your personal data. Requests are handled within the scope of applicable laws and our information notices.</p><p class=\\\"text-white/80\\\">For cookies, please use the cookie preferences and Cookie Policy page.</p></div></section>\"}','Ensotek Privacy Policy: data collected on the website, purposes of processing, retention, security and user rights.','Ensotek Privacy Policy page','Privacy Policy | Ensotek','Ensotek Privacy Policy explains what data we collect, why we process it, how we protect it, and what rights users have.','ensotek,corporate,privacy policy,data protection,cookies,security','2026-03-23 04:11:28.802','2026-03-23 04:11:28.802'),('5dda4d66-266e-11f1-8a30-dc46281c36a8','55550002-5555-4555-8555-555555550002','de','Datenschutzerklärung','datenschutzerklaerung','{\"html\": \"<section class=\\\"container mx-auto px-4 py-10\\\"><h1 class=\\\"text-3xl md:text-4xl font-semibold text-slate-900 mb-4\\\">Datenschutzerklärung</h1><p class=\\\"text-slate-700 mb-8\\\">Ensotek verpflichtet sich, die Privatsphäre der Besucher zu schützen und personenbezogene Daten im Einklang mit den anwendbaren gesetzlichen Vorgaben zu verarbeiten. Diese Erklärung beschreibt Datenkategorien, Zwecke, Speicherfristen, Sicherheitsmaßnahmen und Ihre Rechte.</p><div class=\\\"grid md:grid-cols-2 gap-6 mb-10\\\"><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">1. Geltungsbereich</h2><p class=\\\"text-slate-700\\\">Diese Richtlinie umfasst Daten aus Websitebesuchen, Kontaktformularen, Angebots-/Produktanfragen, E-Mail-Kommunikation und technischen Logs.</p></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">2. Erhobene Daten</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Kontakt: Name, E-Mail, Telefon, Unternehmen/Funktion (falls angegeben)</li><li>Anfrageinhalte: Nachricht, technische Anforderungen, Produktinteresse</li><li>Technische Daten: IP, Browser/Gerät, Seitenaufrufe, Zugriffszeiten, Logs</li><li>Cookies: Nutzungs- und Präferenzdaten (siehe Cookie-Richtlinie)</li></ul></div></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">3. Zwecke</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Bearbeitung von Anfragen, Durchführung von Angebotsprozessen und Kommunikation</li><li>Verbesserung von Sicherheit, Fehleranalyse, Performance und Nutzererlebnis</li><li>Erfüllung gesetzlicher Pflichten und Streitbeilegung</li><li>Informationssicherheit und Business-Continuity</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">4. Speicherdauer</h2><p class=\\\"text-slate-700 mb-3\\\">Daten werden nur so lange gespeichert, wie es für die genannten Zwecke erforderlich ist und/oder gesetzliche Pflichten bestehen.</p><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Kontakt-/Anfragedaten: prozessbezogen + gesetzliche Fristen</li><li>Sicherheits-/Systemlogs: begrenzt nach Sicherheits-/Auditbedarf</li><li>Cookie-Daten: abhängig vom Cookie-Typ</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">5. Dienstleister und Weitergabe</h2><p class=\\\"text-slate-700 mb-3\\\">Eine begrenzte Weitergabe an Dienstleister (Hosting, E-Mail, Sicherheit, Analyse etc.) kann erfolgen und wird durch Verträge sowie Sicherheitsmaßnahmen abgesichert.</p><p class=\\\"text-slate-700\\\">Drittanbieter können eigenen Richtlinien unterliegen. Bitte prüfen Sie die jeweiligen Bedingungen.</p></div><div class=\\\"bg-gradient-to-br from-slate-50 to-blue-50 border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">6. Sicherheitsmaßnahmen</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Zugriffskontrolle und Berechtigungen</li><li>Sichere Kommunikation und Monitoring</li><li>Backups und Notfallmaßnahmen</li><li>Protokollierung und Incident-Management</li></ul></div><div class=\\\"bg-slate-900 text-white rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold mb-3\\\">7. Rechte und Kontakt</h2><p class=\\\"text-white/90 mb-3\\\">Sie können uns bezüglich Ihrer personenbezogenen Daten kontaktieren. Anträge werden im Rahmen der anwendbaren Gesetze und Informationspflichten bearbeitet.</p><p class=\\\"text-white/80\\\">Cookie-Einstellungen verwalten Sie über die Cookie-Hinweise und die Cookie-Richtlinie.</p></div></section>\"}','Ensotek Datenschutzerklärung: Datenkategorien, Zwecke, Aufbewahrung, Sicherheitsmaßnahmen und Rechte der Nutzer.','Ensotek Datenschutzerklärung','Datenschutzerklärung | Ensotek','Die Ensotek Datenschutzerklärung erläutert, welche Daten wir erheben, wofür wir sie verwenden, wie wir sie schützen und welche Rechte Nutzer haben.','ensotek,unternehmen,datenschutz,cookies,sicherheit,personenbezogene daten','2026-03-23 04:11:28.802','2026-03-23 04:11:28.802'),('5ddd1a70-266e-11f1-8a30-dc46281c36a8','55550004-5555-4555-8555-555555550004','tr','Kullanım Koşulları','kullanim-kosullari','{\"html\": \"<section class=\\\"container mx-auto px-4 py-10\\\"><h1 class=\\\"text-3xl md:text-4xl font-semibold text-slate-900 mb-4\\\">Kullanım Koşulları</h1><p class=\\\"text-slate-700 mb-8\\\">Bu web sitesini ziyaret eden veya kullanan herkes aşağıdaki koşulları kabul etmiş sayılır. Koşullar; içerik kullanımını, sorumluluk sınırlarını, üçüncü taraf bağlantılarını ve değişiklik hükümlerini kapsar.</p><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">1. Amaç ve Kapsam</h2><p class=\\\"text-slate-700\\\">Bu koşullar, Ensotek web sitesinin kullanımına ilişkin kuralları ve tarafların hak/yükümlülülüklerini düzenler. Sitedeki içerikler bilgilendirme amaçlıdır.</p></div><div class=\\\"grid md:grid-cols-2 gap-6 mb-6\\\"><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">2. İçerik ve Fikri Mülkiyet</h2><p class=\\\"text-slate-700 mb-3\\\">Sitedeki metin, görsel, logo ve diğer tüm materyaller Ensotek’e veya hak sahiplerine aittir.</p><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>İzinsiz kopyalama/çoğaltma/yayma yapılamaz</li><li>Marka ve logo kullanımı yazılı izne tabidir</li><li>Teknik dokümanlar yalnızca bilgilendirme amaçlı paylaşılır</li></ul></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">3. Kullanıcı Yükümlülükleri</h2><ul class=\\\"list-disc pl-6 text-slate-700 space-y-2\\\"><li>Siteyi hukuka ve ahlaka aykırı amaçlarla kullanmamak</li><li>Sisteme zarar verebilecek girişimlerde bulunmamak</li><li>Yanıltıcı/gerçeğe aykırı bilgi paylaşmamak</li></ul></div></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">4. Sorumluluk Reddi</h2><p class=\\\"text-slate-700 mb-3\\\">Sitede yer alan bilgiler genel bilgilendirme amaçlıdır. Ensotek, içeriğin doğruluğu ve güncelliği için makul çaba gösterir; ancak içeriklerin hatasız olduğu veya her zaman güncel kalacağı yönünde garanti vermez.</p><p class=\\\"text-slate-700\\\">Sitedeki bilgilere dayanarak alınacak kararlardan doğabilecek zararlar kullanıcı sorumluluğundadır.</p></div><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">5. Üçüncü Taraf Bağlantılar</h2><p class=\\\"text-slate-700\\\">Üçüncü taraf sitelere verilen bağlantılar bilgi amaçlıdır. Ensotek bu sitelerin içeriğinden ve uygulamalarından sorumlu değildir.</p></div><div class=\\\"bg-slate-900 text-white rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold mb-3\\\">6. Değişiklikler</h2><p class=\\\"text-white/90\\\">Ensotek, kullanım koşullarını güncelleme hakkını saklı tutar. Güncellemeler web sitesinde yayımlandığı tarihten itibaren geçerlidir.</p></div></section>\"}','Ensotek Kullanım Koşulları: web sitesinin kullanımı, fikri mülkiyet, sorumluluk sınırları ve değişiklik hükümleri.','Ensotek Kullanım Koşulları sayfası','Kullanım Koşulları | Ensotek','Ensotek web sitesi kullanım koşulları: içerik hakları, kullanıcı yükümlülükleri, sorumluluk reddi ve üçüncü taraf bağlantılar.','ensotek,legal,kullanim kosullari,terms,fikri mulkiyet,sorumluluk','2026-03-23 04:11:28.822','2026-03-23 04:11:28.822'),('5ddd5249-266e-11f1-8a30-dc46281c36a8','55550004-5555-4555-8555-555555550004','en','Terms of Use','terms-of-use','{\"html\": \"<section class=\\\"container mx-auto px-4 py-10\\\"><h1 class=\\\"text-3xl md:text-4xl font-semibold text-slate-900 mb-4\\\">Terms of Use</h1><p class=\\\"text-slate-700 mb-8\\\">By accessing or using this website you agree to the terms below. These terms cover content usage, limitation of liability, external links and updates.</p><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6 mb-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">1. Purpose and Scope</h2><p class=\\\"text-slate-700\\\">These terms govern the use of the Ensotek website. Website content is provided for informational purposes only.</p></div><div class=\\\"grid md:grid-cols-2 gap-6 mb-6\\\"><div class=\\\"bg-white border border-slate-200 rounded-2xl p-6\\\"><h2 class=\\\"text-xl font-semibold text-slate-900 mb-3\\\">2. Intellectual Property</h2><p class=\\\"text-slate-700 mb-3\\\">Texts, images, logos and 