  KEY `library_images_asset_idx` (`image_asset_id`),
  CONSTRAINT `fk_library_images_asset` FOREIGN KEY (`image_asset_id`) REFERENCES `storage_assets` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_library_images_library` FOREIGN KEY (`library_id`) REFERENCES `library` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
