UNLOCK TABLES;

--
-- Table structure for table `product_faqs`
--

DROP TABLE IF EXISTS `product_faqs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_faqs` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `product_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `locale` varchar(8) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'de',
  `question` varchar(500) COLLATE utf8mb4_unicode_ci NOT NULL,
  `answer` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `display_order` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  KEY `product_faqs_product_id_idx` (`product_id`),
  KEY `product_faqs_order_idx` (`display_order`),
  KEY `product_faqs_product_locale_idx` (`product_id`,`locale`),
  KEY `product_faqs_locale_idx` (`locale`),
  CONSTRAINT `fk_product_faqs_product` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `product_faqs`
--

LOCK TABLES `product_faqs` WRITE;
/*!40000 ALTER TABLE `product_faqs` DISABLE KEYS */;
INSERT INTO `product_faqs` VALUES ('22220001-aaaa-4aaa-8aaa-bbbb0001tr01','bbbb0001-2222-4222-8222-bbbbbbbb0001','tr','Kapalı tip kule ne zaman tercih edilir?','Soğutulacak suyun kirliliğe/partiküle karşı hassas olduğu ve proses akışkanının temiz kalmasının istendiği uygulamalarda tercih edilir.',10,1,'2026-03-23 04:11:27.814','2026-03-23 04:11:27.814'),('22220001-aaaa-4aaa-8aaa-bbbb0001tr02','bbbb0001-2222-4222-8222-bbbbbbbb0001','tr','Soğutma prensibi nedir?','Proses akışkanı serpantin/boru içinden geçer. Dış tarafta hava akışı ve kulenin sirkülasyon suyu boru yüzeyinden ısıyı alarak içerideki akışkanı soğutur.',20,1,'2026-03-23 04:11:27.814','2026-03-23 04:11:27.814'),('22220001-aaaa-4aaa-8aaa-bbbb0001tr03','bbbb0001-2222-4222-8222-bbbbbbbb0001','tr','Hangi proseslerde kullanılır?','Hava kompresörleri, indüksiyon ocakları ve chiller grupları gibi hassas ekipman içeren proseslerde kullanılır.',30,1,'2026-03-23 04:11:27.814','2026-03-23 04:11:27.814'),('22220001-bbbb-4bbb-8bbb-bbbb0001en01','bbbb0001-2222-4222-8222-bbbbbbbb0001','en','When should a closed circuit tower be preferred?','It is preferred when the water to be cooled is sensitive to contamination and the process fluid must remain clean.',10,1,'2026-03-23 04:11:27.816','2026-03-23 04:11:27.816'),('22220001-bbbb-4bbb-8bbb-bbbb0001en02','bbbb0001-2222-4222-8222-bbbbbbbb0001','en','What is the cooling principle?','The process fluid flows inside the coil. Air flow and circulating water remove heat from the coil surface and cool the fluid inside.',20,1,'2026-03-23 04:11:27.816','2026-03-23 04:11:27.816'),('22220001-bbbb-4bbb-8bbb-bbbb0001en03','bbbb0001-2222-4222-8222-bbbbbbbb0001','en','Typical application areas?','Used in processes with sensitive equipment such as air compressors, induction furnaces and chillers.',30,1,'2026-03-23 04:11:27.816','2026-03-23 04:11:27.816'),('22220001-cccc-4ccc-8ccc-bbbb0001de01','bbbb0001-2222-4222-8222-bbbbbbbb0001','de','Wann ist ein geschlossener Kühlturm sinnvoll?','Wenn das zu kühlende Wasser empfindlich gegenüber Verunreinigungen ist und das Prozessmedium sauber bleiben muss.',10,1,'2026-03-23 04:11:27.819','2026-03-23 04:11:27.819'),('22220001-cccc-4ccc-8ccc-bbbb0001de02','bbbb0001-2222-4222-8222-bbbbbbbb0001','de','Wie funktioniert das Kühlprinzip?','Das Prozessmedium strömt im Coil. Außenluft und Umlaufwasser entziehen über die Coil-Oberfläche Wärme und kühlen das Medium.',20,1,'2026-03-23 04:11:27.819','2026-03-23 04:11:27.819'),('22220001-cccc-4ccc-8ccc-bbbb0001de03','bbbb0001-2222-4222-8222-bbbbbbbb0001','de','Typische Einsatzbereiche?','Häufig in Prozessen mit sensibler Ausrüstung: Luftkompressoren, Induktionsöfen und Chiller-Anlagen.',30,1,'2026-03-23 04:11:27.819','2026-03-23 04:11:27.819'),('22221501-aaaa-4aaa-8aaa-bbbb1501tr01','bbbb1501-2222-4222-8222-bbbbbbbb1501','tr','Motor ve redüktör grubu nerede çalışır?','Kulenin çatı bölümünde; fan ve fan bacası ile birlikte grup halinde çalışır.',10,1,'2026-03-23 04:11:27.871','2026-03-23 04:11:27.871'),('22221501-aaaa-4aaa-8aaa-bbbb1501tr02','bbbb1501-2222-4222-8222-bbbbbbbb1501','tr','Hangi durumda redüktör gerekir?','Fan çapı büyüdükçe (tipik olarak Ø > 1600 mm) motorla birlikte redüktör kullanımı tercih edilir.',20,1,'2026-03-23 04:11:27.871','2026-03-23 04:11:27.871'),('22221501-aaaa-4aaa-8aaa-bbbb1501tr03','bbbb1501-2222-4222-8222-bbbbbbbb1501','tr','Koruma sınıfı nedir?','Motorlar IP56 koruma sınıfı ve F sınıfı izolasyonla toz, yağ ve neme karşı korunur.',30,1,'2026-03-23 04:11:27.871','2026-03-23 04:11:27.871'),('22221501-bbbb-4bbb-8bbb-bbbb1501en01','bbbb1501-2222-4222-8222-bbbbbbbb1501','en','Where does the motor and reducer group operate?','On the tower deck, working together with the fan and fan stack as a single group.',10,1,'2026-03-23 04:11:27.874','2026-03-23 04:11:27.874'),('22221501-bbbb-4bbb-8bbb-bbbb1501en02','bbbb1501-2222-4222-8222-bbbbbbbb1501','en','When is a reducer required?','For larger fan diameters (typically Ø > 1600 mm), motor and reducer are used together.',20,1,'2026-03-23 04:11:27.874','2026-03-23 04:11:27.874'),('22221501-bbbb-4bbb-8bbb-bbbb1501en03','bbbb1501-2222-4222-8222-bbbbbbbb1501','en','What is the protection class?','Motors are IP56 protected and Class F insulated against dust, oil and moisture.',30,1,'2026-03-23 04:11:27.874','2026-03-23 04:11:27.874'),('22221501-cccc-4ccc-8ccc-bbbb1501de01','bbbb1501-2222-4222-8222-bbbbbbbb1501','de','Wo wird die Motor-Getriebeeinheit eingesetzt?','Am Deckteil des Kühlturms, zusammen mit Lüfter und Lüfterstapel.',10,1,'2026-03-23 04:11:27.878','2026-03-23 04:11:27.878'),('22221501-cccc-4ccc-8ccc-bbbb1501de02','bbbb1501-2222-4222-8222-bbbbbbbb1501','de','Wann wird ein Getriebe benötigt?','Bei größeren Ventilatordurchmessern (typisch > Ø 1600 mm) wird Motor + Getriebe verwendet.',20,1,'2026-03-23 04:11:27.878','2026-03-23 04:11:27.878'),('22221501-cccc-4ccc-8ccc-bbbb1501de03','bbbb1501-2222-4222-8222-bbbbbbbb1501','de','Welche Schutzart hat der Motor?','IP56 Schutzart und Isolationsklasse F gegen Staub, Öl und Feuchtigkeit.',30,1,'2026-03-23 04:11:27.878','2026-03-23 04:11:27.878'),('22221502-aaaa-4aaa-8aaa-bbbb1502tr01','bbbb1502-2222-4222-8222-bbbbbbbb1502','tr','Titreşim şalteri nerede kullanılır?','Genellikle redüktörlü kulelerde fan bacasının hemen yanında, fan grubu üzerinde/yanında konumlandırılır.',10,1,'2026-03-23 04:11:27.885','2026-03-23 04:11:27.885'),('22221502-aaaa-4aaa-8aaa-bbbb1502tr02','bbbb1502-2222-4222-8222-bbbbbbbb1502','tr','Ne işe yarar?','Anormal titreşimi algılayarak elektrik motorunu devreden çıkarır ve ekipmanı korur.',20,1,'2026-03-23 04:11:27.885','2026-03-23 04:11:27.885'),('22221502-aaaa-4aaa-8aaa-bbbb1502tr03','bbbb1502-2222-4222-8222-bbbbbbbb1502','tr','Hangi tipleri vardır?','Siviç kontaklı, cıva kontaklı ve manyetik kontaklı tipleri bulunur.',30,1,'2026-03-23 04:11:27.885','2026-03-23 04:11:27.885'),('22221502-bbbb-4bbb-8bbb-bbbb1502en01','bbbb1502-2222-4222-8222-bbbbbbbb1502','en','Where is the vibration switch installed?','Typically next to the fan stack on gear-driven cooling towers.',10,1,'2026-03-23 04:11:27.887','2026-03-23 04:11:27.887'),('22221502-bbbb-4bbb-8bbb-bbbb1502en02','bbbb1502-2222-4222-8222-bbbbbbbb1502','en','What does it do?','It detects abnormal vibration in the fan group and shuts down the motor to protect equipment.',20,1,'2026-03-23 04:11:27.887','2026-03-23 04:11:27.887'),('22221502-bbbb-4bbb-8bbb-bbbb1502en03','bbbb1502-2222-4222-8222-bbbbbbbb1502','en','Which types are available?','Switch-contact, mercury-contact and magnetic-contact types are available.',30,1,'2026-03-23 04:11:27.887','2026-03-23 04:11:27.887'),('22221502-cccc-4ccc-8ccc-bbbb1502de01','bbbb1502-2222-4222-8222-bbbbbbbb1502','de','Wo wird der Vibrationsschalter montiert?','Typischerweise am Deckteil in der Nähe des Lüfterstapels, besonders bei getriebegetriebenen Kühltürmen.',10,1,'2026-03-23 04:11:27.889','2026-03-23 04:11:27.889'),('22221502-cccc-4ccc-8ccc-bbbb1502de02','bbbb1502-2222-4222-8222-bbbbbbbb1502','de','Welche Aufgabe hat er?','Er erkennt Vibrationen bei abnormalen Betriebssituationen und schaltet den Motor ab, um die Anlage zu schützen.',20,1,'2026-03-23 04:11:27.889','2026-03-23 04:11:27.889'),('22221502-cccc-4ccc-8ccc-bbbb1502de03','bbbb1502-2222-4222-8222-bbbbbbbb1502','de','Welche Ausführungen gibt es?','Ausführungen mit Schaltkontakt, Quecksilberkontakt oder Magnetkontakt.',30,1,'2026-03-23 04:11:27.889','2026-03-23 04:11:27.889'),('22221503-aaaa-4aaa-8aaa-bbbb1503tr01','bbbb1503-2222-4222-8222-bbbbbbbb1503','tr','Aksiyal fanın görevi nedir?','Havayı kule boyunca hareket ettirerek dolgulardan geçirir ve fan bacasından atmosfere atılmasını sağlar.',10,1,'2026-03-23 04:11:27.895','2026-03-23 04:11:27.895'),('22221503-aaaa-4aaa-8aaa-bbbb1503tr02','bbbb1503-2222-4222-8222-bbbbbbbb1503','tr','Hangi kanat malzemeleri kullanılabilir?','Cam elyaf takviyeli PP, CTP (FRP), alüminyum pultruzyon profil veya PP seçenekleri bulunur.',20,1,'2026-03-23 04:11:27.895','2026-03-23 04:11:27.895'),('22221503-aaaa-4aaa-8aaa-bbbb1503tr03','bbbb1503-2222-4222-8222-bbbbbbbb1503','tr','Fan seçimi neye göre yapılır?','Kule tipi, fan çapı, debi/çekiş ihtiyacı ve montaj yapısına göre uygun seçenek belirlenir.',30,1,'2026-03-23 04:11:27.895','2026-03-23 04:11:27.895'),('22221503-bbbb-4bbb-8bbb-bbbb1503en01','bbbb1503-2222-4222-8222-bbbbbbbb1503','en','What is the role of an axial fan?','It drives air through louvers and fill media and discharges it via the fan stack to support evaporative cooling.',10,1,'2026-03-23 04:11:27.897','2026-03-23 04:11:27.897'),('22221503-bbbb-4bbb-8bbb-bbbb1503en02','bbbb1503-2222-4222-8222-bbbbbbbb1503','en','Which blade materials are available?','Glass-fiber reinforced PP, FRP (CTP), aluminum pultrusion and PP options are available.',20,1,'2026-03-23 04:11:27.897','2026-03-23 04:11:27.897'),('22221503-bbbb-4bbb-8bbb-bbbb1503en03','bbbb1503-2222-4222-8222-bbbbbbbb1503','en','How do I select the right fan?','Selection depends on tower type, fan diameter, required airflow and mounting configuration.',30,1,'2026-03-23 04:11:27.897','2026-03-23 04:11:27.897'),('22221503-cccc-4ccc-8ccc-bbbb1503de01','bbbb1503-2222-4222-8222-bbbbbbbb1503','de','Welche Aufgabe hat der Axialventilator?','Er bewegt die Luft durch den Turm, durchströmt die Füllkörper und stößt sie über den Lüfterkamin aus.',10,1,'2026-03-23 04:11:27.902','2026-03-23 04:11:27.902'),('22221503-cccc-4ccc-8ccc-bbbb1503de02','bbbb1503-2222-4222-8222-bbbbbbbb1503','de','Welche Materialien gibt es für die Flügel?','Glasfaserverstärktes PP, FRP (CTP), Aluminium-Pultrusionsprofil oder PP.',20,1,'2026-03-23 04:11:27.902','2026-03-23 04:11:27.902'),('22221503-cccc-4ccc-8ccc-bbbb1503de03','bbbb1503-2222-4222-8222-bbbbbbbb1503','de','Wovon hängt die Auswahl ab?','Von Turmtyp, Ventilatordurchmesser, benötigtem Luftstrom und Montageausführung.',30,1,'2026-03-23 04:11:27.902','2026-03-23 04:11:27.902'),('22221504-aaaa-4aaa-8aaa-bbbb1504tr01','bbbb1504-2222-4222-8222-bbbbbbbb1504','tr','Servis penceresi ne işe yarar?','Kule içinin gözlemlenmesini ve bakım personelinin gerekli bölgelere kolay erişimini sağlar.',10,1,'2026-03-23 04:11:27.909','2026-03-23 04:11:27.909'),('22221504-aaaa-4aaa-8aaa-bbbb1504tr02','bbbb1504-2222-4222-8222-bbbbbbbb1504','tr','Nereye montajlanır?','Genellikle kulenin yan duvarına; ihtiyaca göre dolgu alt kotuna yakın bölgeye de uygulanabilir.',20,1,'2026-03-23 04:11:27.909','2026-03-23 04:11:27.909'),('22221504-aaaa-4aaa-8aaa-bbbb1504tr03','bbbb1504-2222-4222-8222-bbbbbbbb1504','tr','Hangi malzemelerden üretilir?','Korozyon dayanımı için paslanmaz çelik veya CTP (FRP) seçenekleri tercih edilir.',30,1,'2026-03-23 04:11:27.909','2026-03-23 04:11:27.909'),('22221504-bbbb-4bbb-8bbb-bbbb1504en01','bbbb1504-2222-4222-8222-bbbbbbbb1504','en','What is a service window used for?','It provides observation and easy access to the tower interior for inspection and maintenance.',10,1,'2026-03-23 04:11:27.911','2026-03-23 04:11:27.911'),('22221504-bbbb-4bbb-8bbb-bbbb1504en02','bbbb1504-2222-4222-8222-bbbbbbbb1504','en','Where is it installed?','Typically on the side wall of the outer casing; it can also be applied near the lower fill level if needed.',20,1,'2026-03-23 04:11:27.911','2026-03-23 04:11:27.911'),('22221504-bbbb-4bbb-8bbb-bbbb1504en03','bbbb1504-2222-4222-8222-bbbbbbbb1504','en','Which materials are available?','Stainless steel and FRP (CTP) options are used for corrosion resistance.',30,1,'2026-03-23 04:11:27.911','2026-03-23 04:11:27.911'),('22221504-cccc-4ccc-8ccc-bbbb1504de01','bbbb1504-2222-4222-8222-bbbbbbbb1504','de','Wofür wird das Servicefenster verwendet?','Es ermöglicht Beobachtung und einen einfachen Zugang ins Turminnere für Kontrolle und Wartung.',10,1,'2026-03-23 04:11:27.912','2026-03-23 04:11:27.912'),('22221504-cccc-4ccc-8ccc-bbbb1504de02','bbbb1504-2222-4222-8222-bbbbbbbb1504','de','Wo wird es montiert?','Typischerweise an der Seitenwand der Außenverkleidung; je nach Bedarf auch nahe der unteren Füllhöhe.',20,1,'2026-03-23 04:11:27.912','2026-03-23 04:11:27.912'),('22221504-cccc-4ccc-8ccc-bbbb1504de03','bbbb1504-2222-4222-8222-bbbbbbbb1504','de','Welche Materialien sind möglich?','Edelstahl oder FRP (CTP) für hohe Korrosionsbeständigkeit.',30,1,'2026-03-23 04:11:27.912','2026-03-23 04:11:27.912'),('22221505-aaaa-4aaa-8aaa-bbbb1505tr01','bbbb1505-2222-4222-8222-bbbbbbbb1505','tr','Su dağıtım sistemi ne işe yarar?','Tesisten gelen sıcak suyu kule içindeki dolgular üzerine eşit şekilde dağıtır.',10,1,'2026-03-23 04:11:27.918','2026-03-23 04:11:27.918'),('22221505-aaaa-4aaa-8aaa-bbbb1505tr02','bbbb1505-2222-4222-8222-bbbbbbbb1505','tr','Hangi sıcaklıkta hangi malzeme kullanılır?','55°C altı uygulamalarda PVC; daha yüksek sıcaklıklarda PP veya CTP (FRP) tercih edilir.',20,1,'2026-03-23 04:11:27.918','2026-03-23 04:11:27.918'),('22221505-aaaa-4aaa-8aaa-bbbb1505tr03','bbbb1505-2222-4222-8222-bbbbbbbb1505','tr','Bakım sırasında sökme-takma kolay mı?','Evet. Sızdırmaz bağlantı yapısı sayesinde kesme/ekleme yapmadan kolayca sökülüp takılabilir.',30,1,'2026-03-23 04:11:27.918','2026-03-23 04:11:27.918'),('22221505-bbbb-4bbb-8bbb-bbbb1505en01','bbbb1505-2222-4222-8222-bbbbbbbb1505','en','What does the water distribution system do?','It distributes hot water from the plant uniformly onto the tower fill media.',10,1,'2026-03-23 04:11:27.919','2026-03-23 04:11:27.919'),('22221505-bbbb-4bbb-8bbb-bbbb1505en02','bbbb1505-2222-4222-8222-bbbbbbbb1505','en','Which material is used at different temperatures?','PVC is used below 55°C; PP or FRP (CTP) is preferred above 55°C.',20,1,'2026-03-23 04:11:27.919','2026-03-23 04:11:27.919'),('22221505-bbbb-4bbb-8bbb-bbbb1505en03','bbbb1505-2222-4222-8222-bbbbbbbb1505','en','Is maintenance easy?','Yes. Leak-tight joints allow easy assembly/disassembly without cutting or splicing.',30,1,'2026-03-23 04:11:27.919','2026-03-23 04:11:27.919'),('22221505-cccc-4ccc-8ccc-bbbb1505de01','bbbb1505-2222-4222-8222-bbbbbbbb1505','de','Wofür ist das Wasserverteilungssystem zuständig?','Es verteilt das heiße Wasser aus der Anlage gleichmäßig auf die Füllkörper im Turm.',10,1,'2026-03-23 04:11:27.922','2026-03-23 04:11:27.922'),('22221505-cccc-4ccc-8ccc-bbbb1505de02','bbbb1505-2222-4222-8222-bbbbbbbb1505','de','Welches Material wird bei welchen Temperaturen verwendet?','Unter 55°C PVC; bei höheren Temperaturen PP oder FRP (CTP).',20,1,'2026-03-23 04:11:27.922','2026-03-23 04:11:27.922'),('22221505-cccc-4ccc-8ccc-bbbb1505de03','bbbb1505-2222-4222-8222-bbbbbbbb1505','de','Ist die Wartung einfach?','Ja. Durch dichtende Verbindungen ist die Montage/Demontage ohne Schneiden und Einfügen möglich.',30,1,'2026-03-23 04:11:27.922','2026-03-23 04:11:27.922'),('22221506-aaaa-4aaa-8aaa-bbbb1506tr01','bbbb1506-2222-4222-8222-bbbbbbbb1506','tr','Nozul hangi malzemeden üretilir?','Polipropilen (PP) malzemeden üretilir.',10,1,'2026-03-23 04:11:27.928','2026-03-23 04:11:27.928'),('22221506-aaaa-4aaa-8aaa-bbbb1506tr02','bbbb1506-2222-4222-8222-bbbbbbbb1506','tr','Basınç veya debi ayarı yapılabilir mi?','Evet. Farklı çap konik parçalar kullanılarak basınç/debi ayarı yapılabilir.',20,1,'2026-03-23 04:11:27.928','2026-03-23 04:11:27.928'),('22221506-aaaa-4aaa-8aaa-bbbb1506tr03','bbbb1506-2222-4222-8222-bbbbbbbb1506','tr','Bakım ve temizlik kolay mı?','Evet. Kolay sök/tak tasarımı sayesinde temizlik ve bakım için uygundur.',30,1,'2026-03-23 04:11:27.928','2026-03-23 04:11:27.928'),('22221506-bbbb-4bbb-8bbb-bbbb1506en01','bbbb1506-2222-4222-8222-bbbbbbbb1506','en','Which material is the nozzle made of?','It is made of polypropylene (PP).',10,1,'2026-03-23 04:11:27.932','2026-03-23 04:11:27.932'),('22221506-bbbb-4bbb-8bbb-bbbb1506en02','bbbb1506-2222-4222-8222-bbbbbbbb1506','en','Can pressure or flow be adjusted?','Yes. Pressure/flow can be adjusted using cones with different diameters.',20,1,'2026-03-23 04:11:27.932','2026-03-23 04:11:27.932'),('22221506-bbbb-4bbb-8bbb-bbbb1506en03','bbbb1506-2222-4222-8222-bbbbbbbb1506','en','Is maintenance easy?','Yes. The design allows easy removal/installation for cleaning and maintenance.',30,1,'2026-03-23 04:11:27.932','2026-03-23 04:11:27.932'),('22221506-cccc-4ccc-8ccc-bbbb1506de01','bbbb1506-2222-4222-8222-bbbbbbbb1506','de','Aus welchem Material besteht die Düse?','Sie besteht aus Polypropylen (PP).',10,1,'2026-03-23 04:11:27.934','2026-03-23 04:11:27.934'),('22221506-cccc-4ccc-8ccc-bbbb1506de02','bbbb1506-2222-4222-8222-bbbbbbbb1506','de','Kann man Druck oder Durchfluss einstellen?','Ja. Über Kegel mit unterschiedlichen Durchmessern lässt sich Druck/Durchfluss einstellen.',20,1,'2026-03-23 04:11:27.934','2026-03-23 04:11:27.934'),('22221506-cccc-4ccc-8ccc-bbbb1506de03','bbbb1506-2222-4222-8222-bbbbbbbb1506','de','Ist die Wartung einfach?','Ja. Die Konstruktion ermöglicht eine leichte Montage/Demontage zur Reinigung.',30,1,'2026-03-23 04:11:27.934','2026-03-23 04:11:27.934'),('22221507-aaaa-4aaa-8aaa-bbbb1507tr01','bbbb1507-2222-4222-8222-bbbbbbbb1507','tr','Pultruzyon profil nedir?','Elyaf ve reçinenin kalıptan sürekli geçirilmesiyle üretilen, yüksek mukavemetli kompozit profildir.',10,1,'2026-03-23 04:11:27.944','2026-03-23 04:11:27.944'),('22221507-aaaa-4aaa-8aaa-bbbb1507tr02','bbbb1507-2222-4222-8222-bbbbbbbb1507','tr','CTP profillerin avantajı nedir?','Yüksek dayanım, korozyon/kimyasal dayanım ve bakım/boya gerektirmeyen uzun ömür sağlar.',20,1,'2026-03-23 04:11:27.944','2026-03-23 04:11:27.944'),('22221507-aaaa-4aaa-8aaa-bbbb1507tr03','bbbb1507-2222-4222-8222-bbbbbbbb1507','tr','Hangi alanlarda kullanılır?','Soğutma kulesi konstrüksiyonunda farklı kesitli taşıyıcı/bağlantı profilleri olarak kullanılır.',30,1,'2026-03-23 04:11:27.944','2026-03-23 04:11:27.944'),('22221507-bbbb-4bbb-8bbb-bbbb1507en01','bbbb1507-2222-4222-8222-bbbbbbbb1507','en','What is a pultrusion profile?','A composite profile produced by pulling fiber and resin through a die, resulting in high strength and consistency.',10,1,'2026-03-23 04:11:27.946','2026-03-23 04:11:27.946'),('22221507-bbbb-4bbb-8bbb-bbbb1507en02','bbbb1507-2222-4222-8222-bbbbbbbb1507','en','What are the key advantages of FRP profiles?','High strength, corrosion/chemical resistance, and long service life without painting or periodic maintenance.',20,1,'2026-03-23 04:11:27.946','2026-03-23 04:11:27.946'),('22221507-bbbb-4bbb-8bbb-bbbb1507en03','bbbb1507-2222-4222-8222-bbbbbbbb1507','en','Where are they used in cooling towers?','As structural and connection profiles with various cross-sections in tower construction.',30,1,'2026-03-23 04:11:27.946','2026-03-23 04:11:27.946'),('22221507-cccc-4ccc-8ccc-bbbb1507de01','bbbb1507-2222-4222-8222-bbbbbbbb1507','de','Was ist ein Pultrusionsprofil?','Ein Verbundprofil, das durch kontinuierliches Ziehen von Faser und Harz durch eine Matrize hergestellt wird.',10,1,'2026-03-23 04:11:27.948','2026-03-23 04:11:27.948'),('22221507-cccc-4ccc-8ccc-bbbb1507de02','bbbb1507-2222-4222-8222-bbbbbbbb1507','de','Welche Vorteile haben FRP/GFK-Profile?','Hohe Festigkeit, Korrosions-/Chemikalienbeständigkeit und lange Lebensdauer ohne Lackierung oder regelmäßige Wartung.',20,1,'2026-03-23 04:11:27.948','2026-03-23 04:11:27.948'),('22221507-cccc-4ccc-8ccc-bbbb1507de03','bbbb1507-2222-4222-8222-bbbbbbbb1507','de','Wo werden sie im Kühlturm eingesetzt?','Als Konstruktions- und Verbindungsprofile mit unterschiedlichen Querschnitten im Turmbau.',30,1,'2026-03-23 04:11:27.948','2026-03-23 04:11:27.948'),('22221508-aaaa-4aaa-8aaa-bbbb1508tr01','bbbb1508-2222-4222-8222-bbbbbbbb1508','tr','Damlalık ne işe yarar?','Su damlacıklarının hava ile sürüklenerek atmosfere taşınmasını azaltır ve su kaybını önler.',10,1,'2026-03-23 04:11:27.955','2026-03-23 04:11:27.955'),('22221508-aaaa-4aaa-8aaa-bbbb1508tr02','bbbb1508-2222-4222-8222-bbbbbbbb1508','tr','Nerede konumlandırılır?','Fan grubunun bulunduğu platform ile su dağıtım sistemi arasında yer alır.',20,1,'2026-03-23 04:11:27.955','2026-03-23 04:11:27.955'),('22221508-aaaa-4aaa-8aaa-bbbb1508tr03','bbbb1508-2222-4222-8222-bbbbbbbb1508','tr','Montaj tipi nasıldır?','Modüler kasetler halinde, boşluksuz şekilde monte edilerek tüm kesit kapatılır.',30,1,'2026-03-23 04:11:27.955','2026-03-23 04:11:27.955'),('22221508-bbbb-4bbb-8bbb-bbbb1508en01','bbbb1508-2222-4222-8222-bbbbbbbb1508','en','What do drift eliminators do?','They reduce water droplet carryover to the atmosphere and help prevent water loss.',10,1,'2026-03-23 04:11:27.956','2026-03-23 04:11:27.956'),('22221508-bbbb-4bbb-8bbb-bbbb1508en02','bbbb1508-2222-4222-8222-bbbbbbbb1508','en','Where are they installed?','Between the fan deck platform and the water distribution system inside the tower.',20,1,'2026-03-23 04:11:27.956','2026-03-23 04:11:27.956'),('22221508-bbbb-4bbb-8bbb-bbbb1508en03','bbbb1508-2222-4222-8222-bbbbbbbb1508','en','How are they mounted?','As modular cassette blocks mounted without gaps to cover the full cross-section.',30,1,'2026-03-23 04:11:27.956','2026-03-23 04:11:27.956'),('22221508-cccc-4ccc-8ccc-bbbb1508de01','bbbb1508-2222-4222-8222-bbbbbbbb1508','de','Wozu dient ein Tropfenabscheider?','Er reduziert die Tröpfchenmitnahme in die Atmosphäre und verhindert Wasserverlust.',10,1,'2026-03-23 04:11:27.961','2026-03-23 04:11:27.961'),('22221508-cccc-4ccc-8ccc-bbbb1508de02','bbbb1508-2222-4222-8222-bbbbbbbb1508','de','Wo wird er montiert?','Zwischen Lüfterplattform und Wasserverteilungssystem im Inneren des Turms.',20,1,'2026-03-23 04:11:27.961','2026-03-23 04:11:27.961'),('22221508-cccc-4ccc-8ccc-bbbb1508de03','bbbb1508-2222-4222-8222-bbbbbbbb1508','de','Wie erfolgt die Montage?','Als modulare Kassetten, die ohne Zwischenräume den gesamten Querschnitt abdecken.',30,1,'2026-03-23 04:11:27.961','2026-03-23 04:11:27.961'),('22221509-aaaa-4aaa-8aaa-bbbb1509tr01','bbbb1509-2222-4222-8222-bbbbbbbb1509','tr','PVC petek dolgu hangi şartlarda tercih edilir?','Genellikle temiz su proseslerinde ve su sıcaklığının 55 °C altında olduğu uygulamalarda tercih edilir.',10,1,'2026-03-23 04:11:27.971','2026-03-23 04:11:27.971'),('22221509-aaaa-4aaa-8aaa-bbbb1509tr02','bbbb1509-2222-4222-8222-bbbbbbbb1509','tr','Film tipi dolgunun avantajı nedir?','Yüksek yüzey alanı sayesinde ısı transfer verimi yüksektir.',20,1,'2026-03-23 04:11:27.971','2026-03-23 04:11:27.971'),('22221509-aaaa-4aaa-8aaa-bbbb1509tr03','bbbb1509-2222-4222-8222-bbbbbbbb1509','tr','CF tipleri neyi ifade eder?','Farklı geometri ve adım (pitch) seçeneklerini ifade eder. Uygulamaya göre CF-12/19/30/CF-M/CF-O seçilir.',30,1,'2026-03-23 04:11:27.971','2026-03-23 04:11:27.971'),('22221509-bbbb-4bbb-8bbb-bbbb1509en01','bbbb1509-2222-4222-8222-bbbbbbbb1509','en','When should PVC film fill be used?','It is recommended for clean-water applications up to about 55 °C with low fouling and scaling.',10,1,'2026-03-23 04:11:27.973','2026-03-23 04:11:27.973'),('22221509-bbbb-4bbb-8bbb-bbbb1509en02','bbbb1509-2222-4222-8222-bbbbbbbb1509','en','What is the main advantage of film fill?','High surface area, which increases heat transfer efficiency.',20,1,'2026-03-23 04:11:27.973','2026-03-23 04:11:27.973'),('22221509-bbbb-4bbb-8bbb-bbbb1509en03','bbbb1509-2222-4222-8222-bbbbbbbb1509','en','What do CF types indicate?','They represent different geometries/pitches. Selection depends on water quality and operating conditions.',30,1,'2026-03-23 04:11:27.973','2026-03-23 04:11:27.973'),('22221509-cccc-4ccc-8ccc-bbbb1509de01','bbbb1509-2222-4222-8222-bbbbbbbb1509','de','Wann wird PVC-Folienfüllung eingesetzt?','Bei sauberem Wasser und Wassertemperaturen bis etwa 55 °C, wenn geringe Verschmutzung/Verkalkung vorliegt.',10,1,'2026-03-23 04:11:27.978','2026-03-23 04:11:27.978'),('22221509-cccc-4ccc-8ccc-bbbb1509de02','bbbb1509-2222-4222-8222-bbbbbbbb1509','de','Was ist der Vorteil von Filmfüllung?','Hohe Oberfläche und damit sehr gute Wärmeübertragungsleistung.',20,1,'2026-03-23 04:11:27.978','2026-03-23 04:11:27.978'),('22221509-cccc-4ccc-8ccc-bbbb1509de03','bbbb1509-2222-4222-8222-bbbbbbbb1509','de','Wofür stehen die CF-Typen?','Sie kennzeichnen unterschiedliche Geometrien/Teilungen. Die Auswahl erfolgt je nach Wasserqualität und Betriebsbedingungen.',30,1,'2026-03-23 04:11:27.978','2026-03-23 04:11:27.978'),('22221510-aaaa-4aaa-8aaa-bbbb1510tr01','bbbb1510-2222-4222-8222-bbbbbbbb1510','tr','PP bigudi dolgu hangi uygulamalar için uygundur?','Kirli, yağlı, kumlu ve kireçlenmeye yatkın proses sularında ve tozlu tesis koşullarında tercih edilir.',10,1,'2026-03-23 04:11:27.985','2026-03-23 04:11:27.985'),('22221510-aaaa-4aaa-8aaa-bbbb1510tr02','bbbb1510-2222-4222-8222-bbbbbbbb1510','tr','Yüksek sıcaklıkta kullanılabilir mi?','Evet, PP bigudi dolgu yaklaşık 100 °C’ye kadar proses sularında kullanılabilir.',20,1,'2026-03-23 04:11:27.985','2026-03-23 04:11:27.985'),('22221510-aaaa-4aaa-8aaa-bbbb1510tr03','bbbb1510-2222-4222-8222-bbbbbbbb1510','tr','Temizlenip tekrar kullanılabilir mi?','Evet. Yıkanarak tekrar kullanılabilir; bakım ve değişim maliyetini düşürür.',30,1,'2026-03-23 04:11:27.985','2026-03-23 04:11:27.985'),('22221510-bbbb-4bbb-8bbb-bbbb1510en01','bbbb1510-2222-4222-8222-bbbbbbbb1510','en','Where is PP ring fill typically used?','In applications with dirty, oily or sandy water and in dusty environments where fouling and scaling are concerns.',10,1,'2026-03-23 04:11:27.990','2026-03-23 04:11:27.990'),('22221510-bbbb-4bbb-8bbb-bbbb1510en02','bbbb1510-2222-4222-8222-bbbbbbbb1510','en','Can it handle high temperature water?','Yes. PP ring fill can be used with process water up to about 100 °C.',20,1,'2026-03-23 04:11:27.990','2026-03-23 04:11:27.990'),('22221510-bbbb-4bbb-8bbb-bbbb1510en03','bbbb1510-2222-4222-8222-bbbbbbbb1510','en','Is it reusable after cleaning?','Yes. It can be washed and reused, reducing maintenance and replacement costs.',30,1,'2026-03-23 04:11:27.990','2026-03-23 04:11:27.990'),('22221510-cccc-4ccc-8ccc-bbbb1510de01','bbbb1510-2222-4222-8222-bbbbbbbb1510','de','Wann ist Spritzring-Füllung sinnvoll?','Bei stark verschmutztem/öligem/sandigem Wasser und in staubigen Umgebungen, wo Fouling und Verkalkung auftreten.',10,1,'2026-03-23 04:11:27.991','2026-03-23 04:11:27.991'),('22221510-cccc-4ccc-8ccc-bbbb1510de02','bbbb1510-2222-4222-8222-bbbbbbbb1510','de','Ist sie für hohe Temperaturen geeignet?','Ja. Sie kann mit Prozesswasser bis ca. 100 °C eingesetzt werden.',20,1,'2026-03-23 04:11:27.991','2026-03-23 04:11:27.991'),('22221510-cccc-4ccc-8ccc-bbbb1510de03','bbbb1510-2222-4222-8222-bbbbbbbb1510','de','Kann sie wiederverwendet werden?','Ja. Nach Reinigung kann sie wiederverwendet werden, die Kosten bleiben gering.',30,1,'2026-03-23 04:11:27.991','2026-03-23 04:11:27.991'),('22221511-aaaa-4aaa-8aaa-bbbb1511tr01','bbbb1511-2222-4222-8222-bbbbbbbb1511','tr','Splash grid dolgu ne zaman tercih edilir?','Su çok kirliyse ve dolgu üzerinde tıkanma riski yüksekse splash grid dolgu tercih edilir.',10,1,'2026-03-23 04:11:27.998','2026-03-23 04:11:27.998'),('22221511-aaaa-4aaa-8aaa-bbbb1511tr02','bbbb1511-2222-4222-8222-bbbbbbbb1511','tr','Hangi sektörlerde kullanımı yaygındır?','Domates salçası üretimi, yağ fabrikası vakum hatları ve haddehaneler gibi tesislerde yaygındır.',20,1,'2026-03-23 04:11:27.998','2026-03-23 04:11:27.998'),('22221511-aaaa-4aaa-8aaa-bbbb1511tr03','bbbb1511-2222-4222-8222-bbbbbbbb1511','tr','Bakım açısından avantajı nedir?','Tıkanmaya daha toleranslı olduğu için temizleme ve bakım periyodunu kolaylaştırır.',30,1,'2026-03-23 04:11:27.998','2026-03-23 04:11:27.998'),('22221511-bbbb-4bbb-8bbb-bbbb1511en01','bbbb1511-2222-4222-8222-bbbbbbbb1511','en','When should splash grid fill be selected?','When water is very dirty and clogging risk is high, splash grid fill is a practical choice.',10,1,'2026-03-23 04:11:28.000','2026-03-23 04:11:28.000'),('22221511-bbbb-4bbb-8bbb-bbbb1511en02','bbbb1511-2222-4222-8222-bbbbbbbb1511','en','Which industries commonly use it?','Common uses include tomato paste plants, vacuum lines in oil factories, and rolling mills.',20,1,'2026-03-23 04:11:28.000','2026-03-23 04:11:28.000'),('22221511-bbbb-4bbb-8bbb-bbbb1511en03','bbbb1511-2222-4222-8222-bbbbbbbb1511','en','What is the maintenance advantage?','Its clogging-tolerant structure typically reduces cleaning frequency and simplifies upkeep.',30,1,'2026-03-23 04:11:28.000','2026-03-23 04:11:28.000'),('22221511-cccc-4ccc-8ccc-bbbb1511de01','bbbb1511-2222-4222-8222-bbbbbbbb1511','de','Wann ist Spritzgitter-Füllung sinnvoll?','Wenn das Wasser stark verschmutzt ist und ein hohes Verstopfungsrisiko besteht.',10,1,'2026-03-23 04:11:28.002','2026-03-23 04:11:28.002'),('22221511-cccc-4ccc-8ccc-bbbb1511de02','bbbb1511-2222-4222-8222-bbbbbbbb1511','de','Wo wird sie typischerweise eingesetzt?','In Tomatenmarkproduktion, Vakuumleitungen von Ölfabriken und in Walzwerken.',20,1,'2026-03-23 04:11:28.002','2026-03-23 04:11:28.002'),('22221511-cccc-4ccc-8ccc-bbbb1511de03','bbbb1511-2222-4222-8222-bbbbbbbb1511','de','Was ist der Wartungsvorteil?','Die tolerante Struktur reduziert Verstopfung und vereinfacht Reinigung und Wartung.',30,1,'2026-03-23 04:11:28.002','2026-03-23 04:11:28.002'),('22221512-aaaa-4aaa-8aaa-bbbb1512tr01','bbbb1512-2222-4222-8222-bbbbbbbb1512','tr','Rashing halkası nerelerde kullanılır?','Soğutma kulelerinde dolgu malzemesi olarak, scrubber/yıkayıcı sistemlerde ise gaz-sıvı temas yüzeyini artırmak için kullanılır.',10,1,'2026-03-23 04:11:28.011','2026-03-23 04:11:28.011'),('22221512-aaaa-4aaa-8aaa-bbbb1512tr02','bbbb1512-2222-4222-8222-bbbbbbbb1512','tr','Scrubber sistemlerinde ne işe yarar?','Gazın temizleme sıvısı ile temas yüzeyini artırır; yıkama ve yoğuşturma ile koku giderimi ve arıtıma katkı sağlar.',20,1,'2026-03-23 04:11:28.011','2026-03-23 04:11:28.011'),('22221512-aaaa-4aaa-8aaa-bbbb1512tr03','bbbb1512-2222-4222-8222-bbbbbbbb1512','tr','Boyut ve paket bilgisi nedir?','Standart ölçü Ø 37 mm x 37 mm’dir; 5.000 adet/torba ve 18.500 adet/m³ değerleri ile kullanılır.',30,1,'2026-03-23 04:11:28.011','2026-03-23 04:11:28.011'),('22221512-bbbb-4bbb-8bbb-bbbb1512en01','bbbb1512-2222-4222-8222-bbbbbbbb1512','en','Where are Raschig rings used?','They are used as fill media in cooling towers and as packing media in scrubber systems.',10,1,'2026-03-23 04:11:28.012','2026-03-23 04:11:28.012'),('22221512-bbbb-4bbb-8bbb-bbbb1512en02','bbbb1512-2222-4222-8222-bbbbbbbb1512','en','What do they do in scrubbers?','They increase gas–liquid contact area to support washing/condensation for odor control and treatment.',20,1,'2026-03-23 04:11:28.012','2026-03-23 04:11:28.012'),('22221512-bbbb-4bbb-8bbb-bbbb1512en03','bbbb1512-2222-4222-8222-bbbbbbbb1512','en','What are the standard size and packaging?','Standard size is Ø 37 mm x 37 mm; packaging is 5,000 pcs/bag; typical bulk is 18,500 pcs/m³.',30,1,'2026-03-23 04:11:28.012','2026-03-23 04:11:28.012'),('22221512-cccc-4ccc-8ccc-bbbb1512de01','bbbb1512-2222-4222-8222-bbbbbbbb1512','de','Wo werden Raschig-Ringe eingesetzt?','Als Füllkörper in Kühltürmen und als Packung in Wäscheranlagen (Scrubber).',10,1,'2026-03-23 04:11:28.015','2026-03-23 04:11:28.015'),('22221512-cccc-4ccc-8ccc-bbbb1512de02','bbbb1512-2222-4222-8222-bbbbbbbb1512','de','Welche Funktion haben sie im Scrubber?','Sie vergrößern die Gas-Flüssig-Kontaktfläche und unterstützen Geruchs- und Emissionsminderung.',20,1,'2026-03-23 04:11:28.015','2026-03-23 04:11:28.015'),('22221512-cccc-4ccc-8ccc-bbbb1512de03','bbbb1512-2222-4222-8222-bbbbbbbb1512','de','Welche Standarddaten gelten?','Ø 37 mm x 37 mm, 5.000 Stück/Beutel und 18.500 Stück/m³.',30,1,'2026-03-23 04:11:28.015','2026-03-23 04:11:28.015'),('22221513-aaaa-4aaa-8aaa-bbbb1513tr01','bbbb1513-2222-4222-8222-bbbbbbbb1513','tr','Hava giriş panjuru ne işe yarar?','Kuleye giren havayı yönlendirerek dolguya daha homojen yayılmasını sağlar; sıçrama su kaybını ve yosun oluşumunu azaltmaya yardımcı olur.',10,1,'2026-03-23 04:11:28.021','2026-03-23 04:11:28.021'),('22221513-aaaa-4aaa-8aaa-bbbb1513tr02','bbbb1513-2222-4222-8222-bbbbbbbb1513','tr','Hangi malzemeden üretilir?','Standart olarak 1. sınıf PVC lameller kullanılır. İstenirse FRP/CTP malzemeden de üretilebilir.',20,1,'2026-03-23 04:11:28.021','2026-03-23 04:11:28.021'),('22221513-aaaa-4aaa-8aaa-bbbb1513tr03','bbbb1513-2222-4222-8222-bbbbbbbb1513','tr','Hangi kule tipleriyle uyumludur?','Yerli ve ithal paket kule tiplerine uygulanabilir.',30,1,'2026-03-23 04:11:28.021','2026-03-23 04:11:28.021'),('22221513-bbbb-4bbb-8bbb-bbbb1513en01','bbbb1513-2222-4222-8222-bbbbbbbb1513','en','What do air inlet louvers do?','They guide incoming air for uniform distribution across the fill, reduce splash water losses, and help limit algae growth by reducing sunlight.',10,1,'2026-03-23 04:11:28.023','2026-03-23 04:11:28.023'),('22221513-bbbb-4bbb-8bbb-bbbb1513en02','bbbb1513-2222-4222-8222-bbbbbbbb1513','en','Which materials are available?','First-grade PVC is standard; FRP can be supplied on request.',20,1,'2026-03-23 04:11:28.023','2026-03-23 04:11:28.023'),('22221513-bbbb-4bbb-8bbb-bbbb1513en03','bbbb1513-2222-4222-8222-bbbbbbbb1513','en','Are they compatible with packaged towers?','Yes. They can be applied to both local and imported packaged tower types.',30,1,'2026-03-23 04:11:28.023','2026-03-23 04:11:28.023'),('22221513-cccc-4ccc-8ccc-bbbb1513de01','bbbb1513-2222-4222-8222-bbbbbbbb1513','de','Wozu dienen Lufteinlasslamellen?','Sie richten die einströmende Luft aus, reduzieren Spritzwasserverluste und helfen, die Algenbildung durch Abschattung zu verringern.',10,1,'2026-03-23 04:11:28.025','2026-03-23 04:11:28.025'),('22221513-cccc-4ccc-8ccc-bbbb1513de02','bbbb1513-2222-4222-8222-bbbbbbbb1513','de','Aus welchem Material bestehen sie?','Standard ist PVC der 1. Klasse; auf Wunsch sind FRP-Ausführungen möglich.',20,1,'2026-03-23 04:11:28.025','2026-03-23 04:11:28.025'),('22221513-cccc-4ccc-8ccc-bbbb1513de03','bbbb1513-2222-4222-8222-bbbbbbbb1513','de','Für welche Kühltürme sind sie geeignet?','Für lokale und importierte Paketkühltürme.',30,1,'2026-03-23 04:11:28.025','2026-03-23 04:11:28.025'),('66660002-aaaa-4aaa-8aaa-bbbb0002tr01','bbbb0002-2222-4222-8222-bbbbbbbb0002','tr','CTP serisi neyi ifade eder?','CTP, tek hücreli açık tip kuleler için ürün ailesini ifade eder. Modeller CTP-1’den CTP-35’e kadar ölçeklenir.',10,1,'2026-03-23 04:11:27.826','2026-03-23 04:11:27.826'),('66660002-aaaa-4aaa-8aaa-bbbb0002tr02','bbbb0002-2222-4222-8222-bbbbbbbb0002','tr','Kapasite değerleri hangi koşullarda veriliyor?','Katalog tablosunda 35/30/25°C ve 40/30/24°C koşulları için kapasite ve debi değerleri paylaşılır.',20,1,'2026-03-23 04:11:27.826','2026-03-23 04:11:27.826'),('66660002-aaaa-4aaa-8aaa-bbbb0002tr03','bbbb0002-2222-4222-8222-bbbbbbbb0002','tr','Doğru model seçimi nasıl yapılır?','Hedef soğutma koşulu (örn. 35/30/25°C), ihtiyaç debisi (m³/h) ve saha yerleşimi (taban ölçüsü/yükseklik) birlikte değerlendirilerek seçilir.',30,1,'2026-03-23 04:11:27.826','2026-03-23 04:11:27.826'),('66660002-bbbb-4bbb-8bbb-bbbb0002en01','bbbb0002-2222-4222-8222-bbbbbbbb0002','en','What does the CTP series represent?','CTP refers to the single-cell open circuit tower family. Models scale from CTP-1 up to CTP-35.',10,1,'2026-03-23 04:11:27.828','2026-03-23 04:11:27.828'),('66660002-bbbb-4bbb-8bbb-bbbb0002en02','bbbb0002-2222-4222-8222-bbbbbbbb0002','en','Under which conditions are capacities provided?','The catalog table provides capacity and flow rates for 35/30/25°C and 40/30/24°C operating conditions.',20,1,'2026-03-23 04:11:27.828','2026-03-23 04:11:27.828'),('66660002-bbbb-4bbb-8bbb-bbbb0002en03','bbbb0002-2222-4222-8222-bbbbbbbb0002','en','How do I choose the right model?','Select based on target operating condition, required flow rate (m³/h), and installation constraints such as base area and height.',30,1,'2026-03-23 04:11:27.828','2026-03-23 04:11:27.828'),('66660002-cccc-4ccc-8ccc-bbbb0002de01','bbbb0002-2222-4222-8222-bbbbbbbb0002','de','Wofür steht die CTP-Serie?','CTP bezeichnet die Einzelzelle-Produktfamilie der offenen Kühltürme. Die Modelle skalieren von CTP-1 bis CTP-35.',10,1,'2026-03-23 04:11:27.830','2026-03-23 04:11:27.830'),('66660002-cccc-4ccc-8ccc-bbbb0002de02','bbbb0002-2222-4222-8222-bbbbbbbb0002','de','Unter welchen Bedingungen sind die Kapazitäten angegeben?','Die Katalogtabelle enthält Kapazität und Volumenstrom für 35/30/25°C sowie 40/30/24°C.',20,1,'2026-03-23 04:11:27.830','2026-03-23 04:11:27.830'),('66660002-cccc-4ccc-8ccc-bbbb0002de03','bbbb0002-2222-4222-8222-bbbbbbbb0002','de','Wie wähle ich das richtige Modell?','Auswahl anhand Ziel-Betriebsbedingung, benötigtem Volumenstrom (m³/h) und Einbaubedingungen (Grundfläche/Höhe).',30,1,'2026-03-23 04:11:27.830','2026-03-23 04:11:27.830'),('66660003-aaaa-4aaa-8aaa-bbbb0003tr01','bbbb0003-2222-4222-8222-bbbbbbbb0003','tr','İki hücreli kule ne zaman tercih edilir?','Yüksek kapasite ve debi ihtiyaçlarında ve işletme sürekliliği için çift hücreli (redundant) yapı istenen projelerde tercih edilir.',10,1,'2026-03-23 04:11:27.845','2026-03-23 04:11:27.845'),('66660003-aaaa-4aaa-8aaa-bbbb0003tr02','bbbb0003-2222-4222-8222-bbbbbbbb0003','tr','Kapasite değerleri hangi koşullarda veriliyor?','Katalog tablosunda 35/30/25°C ve 40/30/24°C koşullarına göre kapasite (kcal/h) ve debi (m³/h) verilir.',20,1,'2026-03-23 04:11:27.845','2026-03-23 04:11:27.845'),('66660003-aaaa-4aaa-8aaa-bbbb0003tr03','bbbb0003-2222-4222-8222-bbbbbbbb0003','tr','Model seçimi nasıl yapılır?','Hedef koşul, istenen debi, saha ölçüleri (taban alanı/yükseklik) ve ağırlık/taşıma şartları birlikte değerlendirilerek seçilir.',30,1,'2026-03-23 04:11:27.845','2026-03-23 04:11:27.845'),('66660003-bbbb-4bbb-8bbb-bbbb0003en01','bbbb0003-2222-4222-8222-bbbbbbbb0003','en','When should a double-cell tower be preferred?','Preferred for higher capacity/flow projects and when a dual-cell configuration is required for operational continuity.',10,1,'2026-03-23 04:11:27.848','2026-03-23 04:11:27.848'),('66660003-bbbb-4bbb-8bbb-bbbb0003en02','bbbb0003-2222-4222-8222-bbbbbbbb0003','en','Under which conditions are capacities listed?','The catalog table lists capacity (kcal/h) and flow rate (m³/h) for 35/30/25°C and 40/30/24°C operating conditions.',20,1,'2026-03-23 04:11:27.848','2026-03-23 04:11:27.848'),('66660003-bbbb-4bbb-8bbb-bbbb0003en03','bbbb0003-2222-4222-8222-bbbbbbbb0003','en','How do I choose the right model?','Select based on target condition, required flow rate, site constraints (base area/height) and handling/weight constraints.',30,1,'2026-03-23 04:11:27.848','2026-03-23 04:11:27.848'),('66660003-cccc-4ccc-8ccc-bbbb0003de01','bbbb0003-2222-4222-8222-bbbbbbbb0003','de','Wann ist eine Doppelzelle sinnvoll?','Bei hohen Kapazitäts- und Volumenstromanforderungen und wenn eine Doppelzellen-Ausführung für Betriebssicherheit/Redundanz gewünscht ist.',10,1,'2026-03-23 04:11:27.850','2026-03-23 04:11:27.850'),('66660003-cccc-4ccc-8ccc-bbbb0003de02','bbbb0003-2222-4222-8222-bbbbbbbb0003','de','Unter welchen Bedingungen sind die Werte angegeben?','Kapazität (kcal/h) und Volumenstrom (m³/h) sind für 35/30/25°C und 40/30/24°C in der Katalogtabelle angegeben.',20,1,'2026-03-23 04:11:27.850','2026-03-23 04:11:27.850'),('66660003-cccc-4ccc-8ccc-bbbb0003de03','bbbb0003-2222-4222-8222-bbbbbbbb0003','de','Wie wähle ich das passende Modell?','Auswahl anhand Ziel-Betriebsbedingung, benötigtem Volumenstrom (m³/h) sowie Einbauraum (Grundfläche/Höhe) und Gewichts-/Handlinganforderungen.',30,1,'2026-03-23 04:11:27.850','2026-03-23 04:11:27.850'),('66660004-aaaa-4aaa-8aaa-bbbb0004tr01','bbbb0004-2222-4222-8222-bbbbbbbb0004','tr','Üç hücreli kule ne zaman tercih edilir?','Çok yüksek kapasite ve debi gereksinimlerinde, üç hücreli yapı ile ölçeklenebilir performans istendiğinde tercih edilir.',10,1,'2026-03-23 04:11:27.860','2026-03-23 04:11:27.860'),('66660004-aaaa-4aaa-8aaa-bbbb0004tr02','bbbb0004-2222-4222-8222-bbbbbbbb0004','tr','Kapasite/debi değerleri hangi koşullarda veriliyor?','Katalog tablosunda 35/30/25°C ve 40/30/24°C koşullarına göre kapasite (kcal/h) ve debi (m³/h) verilir.',20,1,'2026-03-23 04:11:27.860','2026-03-23 04:11:27.860'),('66660004-aaaa-4aaa-8aaa-bbbb0004tr03','bbbb0004-2222-4222-8222-bbbbbbbb0004','tr','Model seçerken nelere bakılmalı?','İstenen debi, hedef koşul, taban alanı/yükseklik ve sahadaki kaldırma/taşıma şartları birlikte değerlendirilmelidir.',30,1,'2026-03-23 04:11:27.860','2026-03-23 04:11:27.860'),('66660004-bbbb-4bbb-8bbb-bbbb0004en01','bbbb0004-2222-4222-8222-bbbbbbbb0004','en','When should a triple-cell tower be preferred?','Preferred for very high capacity/flow requirements where scalable performance with three cells is needed.',10,1,'2026-03-23 04:11:27.861','2026-03-23 04:11:27.861'),('66660004-bbbb-4bbb-8bbb-bbbb0004en02','bbbb0004-2222-4222-8222-bbbbbbbb0004','en','Under which conditions are values listed?','Capacity (kcal/h) and flow rate (m³/h) are listed for 35/30/25°C and 40/30/24°C in the catalog table.',20,1,'2026-03-23 04:11:27.861','2026-03-23 04:11:27.861'),('66660004-bbbb-4bbb-8bbb-bbbb0004en03','bbbb0004-2222-4222-8222-bbbbbbbb0004','en','Key parameters for model selection?','Required flow rate, target condition, footprint/height constraints, and handling/weight constraints should be evaluated together.',30,1,'2026-03-23 04:11:27.861','2026-03-23 04:11:27.861'),('66660004-cccc-4ccc-8ccc-bbbb0004de01','bbbb0004-2222-4222-8222-bbbbbbbb0004','de','Wann ist eine Dreifachzelle sinnvoll?','Bei sehr hohen Kapazitäts- und Volumenstromanforderungen, wenn skalierbare Leistung über drei Zellen benötigt wird.',10,1,'2026-03-23 04:11:27.863','2026-03-23 04:11:27.863'),('66660004-cccc-4ccc-8ccc-bbbb0004de02','bbbb0004-2222-4222-8222-bbbbbbbb0004','de','Unter welchen Bedingungen sind die Werte angegeben?','Kapazität (kcal/h) und Volumenstrom (m³/h) sind für 35/30/25°C und 40/30/24°C in der Katalogtabelle angegeben.',20,1,'2026-03-23 04:11:27.863','2026-03-23 04:11:27.863'),('66660004-cccc-4ccc-8ccc-bbbb0004de03','bbbb0004-2222-4222-8222-bbbbbbbb0004','de','Wichtige Auswahlparameter?','Erforderlicher Volumenstrom, Zielzustand, Platzbedarf (Grundfläche/Höhe) sowie Gewichts- und Handlinganforderungen.',30,1,'2026-03-23 04:11:27.863','2026-03-23 04:11:27.863');
/*!40000 ALTER TABLE `product_faqs` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `product_i18n`
--

DROP TABLE IF EXISTS `product_i18n`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_i18n` (
  `product_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `locale` varchar(8) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'de',
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `alt` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tags` json DEFAULT (json_array()),
  `specifications` json DEFAULT NULL,
  `meta_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`product_id`,`locale`),
  UNIQUE KEY `product_i18n_locale_slug_uq` (`locale`,`slug`),
