INSERT INTO `projects` VALUES ('33333001-0001-4333-8333-333300000001',1,1,10,'https://www.ensotek.com/upload/17/water-cooling-towers-su-sogutma-kuleleri.jpg',NULL,'Su Soğutma Kulesi','CTP Kaportalı Açık Tip','İstanbul',NULL,2,2,NULL,'2024-01-01','Plaza çatısı · 130 m yükseklik','[\"Açık devre soğutma\",\"FRP kapor\",\"Çatı montajı\",\"Yükseklik projelendirme\"]',NULL,NULL,'[\"CTP\",\"FRP\",\"GRP\",\"HVAC\",\"Açık Tip\",\"Su Soğutma\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0002-4333-8333-333300000002',1,0,20,'https://www.ensotek.com/upload/17/ensotek-su-sogutma-kulesi-ensotek-water-cooling-towers.jpg',NULL,'Su Soğutma Kulesi','CTP Kaportalı Açık Tip','Kahramanmaraş',NULL,NULL,NULL,NULL,'2024-01-01','Ankara Fabrika üretimi','[\"Açık devre soğutma\",\"FRP kapor\",\"Endüstriyel soğutma\"]',NULL,NULL,'[\"CTP\",\"FRP\",\"GRP\",\"HVAC\",\"Açık Tip\",\"Su Soğutma\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0003-4333-8333-333300000003',1,1,30,'https://www.ensotek.com/upload/17/water-cooling-towers-su-sogutma-kuleleri.jpg',NULL,'Su Soğutma Kulesi','CTP 6C — Açık Tip','Gebze, Kocaeli','Arçelik A.Ş.',2,2,NULL,NULL,'2× CTP 6C ünite','[\"Açık devre soğutma\",\"Endüstriyel soğutma\",\"Montaj ve devreye alma\"]','https://www.arcelik.com.tr',NULL,'[\"CTP\",\"FRP\",\"GRP\",\"HVAC\",\"Açık Tip\",\"Endüstriyel\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0004-4333-8333-333300000004',1,1,40,'https://www.ensotek.com/upload/17/ensotek-su-sogutma-kulesi-ensotek-water-cooling-towers.jpg',NULL,'Su Soğutma Kulesi','DCTP 5C — Kapalı Devre','İstanbul','Eczacıbaşı',3,3,NULL,NULL,'3× DCTP 5C ünite','[\"Kapalı devre soğutma\",\"İlaç & kimya soğutma\",\"Serpantinli ısı değiştirici\"]','https://www.eczacibasi.com.tr',NULL,'[\"DCTP\",\"FRP\",\"Kapalı Devre\",\"Serpantin\",\"HVAC\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0005-4333-8333-333300000005',1,1,50,'https://www.ensotek.com/upload/9/tctp-26.jpg',NULL,'Proses Soğutma','TCTP 26B + DCTP 12C — Kapalı Devre','Gebze, Kocaeli','Linde Gaz Türkiye',4,4,NULL,NULL,'3× TCTP 26B + 1× DCTP 12C','[\"Kapalı devre soğutma\",\"Proses gazı soğutma\",\"Endüstriyel servis soğutma\",\"Yüksek kapasite proje\"]','https://www.linde.com.tr',NULL,'[\"TCTP\",\"DCTP\",\"FRP\",\"Kapalı Devre\",\"Proses Soğutma\",\"Gaz Endüstrisi\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0006-4333-8333-333300000006',1,0,60,'https://www.ensotek.com/upload/17/water-cooling-towers-su-sogutma-kuleleri.jpg',NULL,'Su Soğutma Kulesi','DCTP 12 + DCTP 12C — Kapalı Devre',NULL,'HES Kablo',2,2,NULL,NULL,'DCTP 12 (merdiven aksesuarlı) + DCTP 12C','[\"Kapalı devre soğutma\",\"Kablo üretim soğutma\",\"Özel aksesuar montajı\"]',NULL,NULL,'[\"DCTP\",\"FRP\",\"Kapalı Devre\",\"Özel Aksesuar\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0007-4333-8333-333300000007',1,0,70,'https://www.ensotek.com/upload/17/ensotek-su-sogutma-kulesi-ensotek-water-cooling-towers.jpg',NULL,'HVAC & Konaklama','CTP 3C — Açık Tip',NULL,'Green Park Hotels',2,2,NULL,NULL,'2× CTP 3C ünite','[\"Otel soğutma\",\"HVAC soğutma\",\"Sessiz çalışma\",\"Estetik tasarım\"]',NULL,NULL,'[\"CTP\",\"FRP\",\"HVAC\",\"Açık Tip\",\"Otel\",\"Konaklama\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0008-4333-8333-333300000008',1,0,80,'https://www.ensotek.com/upload/17/water-cooling-towers-su-sogutma-kuleleri.jpg',NULL,'HVAC & Ticari','TCTP 9C — Kapalı Devre',NULL,'Orion AVM',1,1,NULL,NULL,'1× TCTP 9C','[\"AVM soğutma\",\"Kapalı devre HVAC\",\"Yıl boyu soğutma hizmeti\"]',NULL,NULL,'[\"TCTP\",\"FRP\",\"Kapalı Devre\",\"HVAC\",\"AVM\"]','2026-03-23 04:11:30.662','2026-03-23 04:11:30.662'),('33333001-0009-4333-8333-333300000009',1,0,90,'https://www.ensotek.com/upload/17/ensotek-su-sogutma-kulesi-ensotek-water-cooling-towers.jpg',NULL,'Su Soğutma Kulesi','CTP 9 — Açık Tip',NULL,'Plastifay',1,1,NULL,NULL,'1× CTP 9','[\"Açık devre soğutma\",\"Plastik se