INSERT INTO `projects_i18n` VALUES ('44444001-0001-4444-8444-444400000001','33333001-0001-4333-8333-333300000001','tr','İstanbul Plaza Çatısı — 2 Adet CTP Kaportalı Açık Tip Su Soğutma Kulesi','istanbul-plaza-catisi-ctp-kapotali-acik-tip-su-sogutma-kulesi','İstanbul\'da 130 metre yüksekliğindeki bir plaza binasının çatısına 2 adet, 2 fanlı CTP Kaportalı Açık Tip su soğutma kulesi başarıyla monte edildi.','{\"html\":\"<p>ENSOTEK İstanbul Fabrikasında üretilen <strong>CTP Kaportalı; 2 adet, 2 fanlı Açık Tip Su Soğutma Kuleleri</strong>, İstanbul\'da 130 metre yüksekliğe sahip bir plaza binasının çatısına başarıyla monte edilmiştir.</p><p>Projenin gerçekleştirildiği bina, şehir merkezinde yüksek katlı bir ticari yapıdır. Soğutma kuleleri, binanın iklimlendirme ve proses soğutma ihtiyacını karşılamak üzere özel olarak projelendirilmiş ve imal edilmiştir.</p><h3>Proje Özellikleri</h3><ul><li>Ürün tipi: CTP Kaportalı Açık Tip Su Soğutma Kulesi</li><li>Adet: 2 ünite</li><li>Fan sayısı: Ünite başına 2 fan</li><li>Kurulum yüksekliği: 130 metre (çatı montajı)</li><li>Üretim tesisi: ENSOTEK İstanbul Fabrikası</li></ul><p>FRP (Cam Elyaf Takviyeli Polyester) gövde yapısı sayesinde kuleler, çevre koşullarına karşı üstün dayanıklılık göstermekte ve uzun yıllar sorunsuz hizmet vermektedir.</p>\",\"description\":\"İstanbul plaça çatısına 2 adet 2 fanlı CTP Kaportalı açık tip su soğutma kulesi montajı.\"}','İstanbul Plaza Çatısı — CTP Kaportalı Açık Tip Su Soğutma Kulesi Montajı','İstanbul Plaza Çatısı CTP Su Soğutma Kulesi — ENSOTEK','İstanbul\'da 130 metre yüksekliğindeki plaza çatısına 2 adet 2 fanlı CTP Kaportalı Açık Tip su soğutma kulesi montajı. ENSOTEK Türkiye.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0002-4444-8444-444400000002','33333001-0002-4333-8333-333300000002','tr','Kahramanmaraş Sanayi Tesisi — CTP Kaportalı Açık Tip Su Soğutma Kulesi','kahramanmaras-sanayi-tesisi-ctp-kapotali-acik-tip-su-sogutma-kulesi','ENSOTEK Ankara Fabrikasında üretilen CTP Kaportalı Açık Tip su soğutma kuleleri Kahramanmaraş\'ta faaliyet gösteren sanayi tesisine başarıyla teslim edildi.','{\"html\":\"<p>ENSOTEK <strong>Ankara Fabrikasında üretilen CTP Kaportalı Açık Tip Su Soğutma Kuleleri</strong>, Kahramanmaraş\'ta faaliyet gösteren bir sanayi tesisi için başarıyla imal edilmiş ve devreye alınmıştır.</p><p>Ankara\'daki üretim tesisimiz, Türkiye\'nin en büyük su soğutma kulesi üretim kapasitesine sahip olup; CTP imalatı, serpantin üretimi ve montaj süreçlerinin tamamı kendi bünyemizde gerçekleştirilmektedir.</p><h3>Proje Özellikleri</h3><ul><li>Ürün tipi: CTP Kaportalı Açık Tip Su Soğutma Kulesi</li><li>Üretim tesisi: ENSOTEK Ankara Fabrikası</li><li>Lokasyon: Kahramanmaraş</li><li>Uygulama: Endüstriyel proses soğutma</li></ul><p>ENSOTEK olarak her projede, müşterilerimizin ihtiyaçlarına özel çözümler sunmakta; tasarımdan üretime, montajdan işletmeye kadar tüm süreçlerde yanlarında olmaktayız.</p>\",\"description\":\"Kahramanmaraş sanayi tesisi için Ankara Fabrika yapımı CTP Kaportalı Açık Tip su soğutma kulesi projesi.\"}','Kahramanmaraş — CTP Kaportalı Açık Tip Su Soğutma Kulesi','Kahramanmaraş Sanayi Tesisi Su Soğutma Kulesi — ENSOTEK','ENSOTEK Ankara Fabrikası yapımı CTP Kaportalı Açık Tip su soğutma kuleleri Kahramanmaraş sanayi tesisine teslim edildi.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0003-4444-8444-444400000003','33333001-0003-4333-8333-333300000003','tr','Arçelik — 2 Adet CTP 6C Açık Tip Su Soğutma Kulesi','arcelik-ctp-6c-acik-tip-su-sogutma-kulesi','Türkiye\'nin önde gelen elektronik ve dayanıklı tüketim malları üreticisi Arçelik\'in üretim tesisine 2 adet CTP 6C model açık tip su soğutma kulesi temin edildi.','{\"html\":\"<p>Türkiye\'nin köklü sanayi kuruluşlarından <strong>Arçelik A.Ş.</strong> bünyesindeki üretim tesisi için <strong>2 adet CTP 6C model Açık Tip Su Soğutma Kulesi</strong> tasarlanmış, üretilmiş ve devreye alınmıştır.</p><h3>Uygulama Detayları</h3><ul><li>Model: CTP 6C (Açık Devre)</li><li>Adet: 2 ünite</li><li>Lokasyon: Gebze, Kocaeli</li><li>Sektör: Dayanıklı Tüketim / Elektronik Üretim</li></ul><h3>CTP 6C Özellikleri</h3><p>CTP 6C, orta-büyük kapasiteli açık devre su soğutma kulesidir. FRP gövde yapısı; korozyona, UV radyasyona ve kimyasal etkilere karşı yüksek direnç göstermektedir.</p>\",\"description\":\"Arçelik üretim tesisi için 2 adet CTP 6C model açık tip su soğutma kulesi projesi — Gebze, Kocaeli.\"}','Arçelik Tesisi — 2 Adet CTP 6C Su Soğutma Kulesi','Arçelik CTP 6C Su Soğutma Kulesi Projesi — ENSOTEK','Arçelik üretim tesisi için ENSOTEK tarafından 2 adet CTP 6C model açık tip su soğutma kulesi temin edildi. Gebze, Kocaeli.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0004-4444-8444-444400000004','33333001-0004-4333-8333-333300000004','tr','Eczacıbaşı — 3 Adet DCTP 5C Kapalı Devre Su Soğutma Kulesi','eczacibasi-dctp-5c-kapali-devre-su-sogutma-kulesi','Türkiye\'nin köklü ilaç ve kimya grubu Eczacıbaşı\'nın tesisine 3 adet DCTP 5C model kapalı devre su soğutma kulesi kuruldu.','{\"html\":\"<p><strong>Eczacıbaşı</strong> bünyesindeki üretim tesisi için <strong>3 adet DCTP 5C model Kapalı Devre Su Soğutma Kulesi</strong> sistemi devreye alınmıştır.</p><h3>Proje Detayları</h3><ul><li>Model: DCTP 5C (Kapalı Devre)</li><li>Adet: 3 ünite</li><li>Lokasyon: İstanbul</li><li>Sektör: İlaç / Kimya</li></ul><h3>Kapalı Devre Soğutmanın Avantajları</h3><p>İlaç ve kimya sektöründe süreç sıvısının dış ortamdan izole edilmesi kritik önem taşır. DCTP 5C modelinde kullanılan serpantinli ısı değiştirici sistemi, proses sıvısının soğutma suyu ile hiçbir zaman temas etmemesini sağlar. Bu sayede ürün kalitesi ve hijyen koşulları korunur.</p>\",\"description\":\"Eczacıbaşı ilaç tesisi için 3 adet DCTP 5C kapalı devre su soğutma kulesi projesi — İstanbul.\"}','Eczacıbaşı — 3 Adet DCTP 5C Kapalı Devre Soğutma Kulesi','Eczacıbaşı DCTP 5C Kapalı Devre Su Soğutma Kulesi — ENSOTEK','Eczacıbaşı ilaç tesisi için ENSOTEK tarafından 3 adet DCTP 5C kapalı devre su soğutma kulesi kuruldu. İstanbul.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0005-4444-8444-444400000005','33333001-0005-4333-8333-333300000005','tr','Linde Gaz — TCTP 26B ve DCTP 12C Kapalı Devre Su Soğutma Sistemi — Gebze','linde-gaz-tctp-26b-dctp-12c-kapali-devre-su-sogutma-kulesi-gebze','Küresel gaz endüstrisi devi Linde Gaz\'ın Gebze tesisi için 3 adet TCTP 26B ve 1 adet DCTP 12C model yüksek kapasiteli kapalı devre su soğutma sistemi kuruldu.','{\"html\":\"<p>Küresel gaz endüstrisinin önde gelen kuruluşu <strong>Linde Gaz Türkiye</strong>\'nin Gebze\'deki proses tesisi için yüksek kapasiteli bir soğutma sistemi kurulmuştur.</p><h3>Sistem Bileşenleri</h3><ul><li>3 adet TCTP 26B — Yüksek kapasiteli ters akışlı kapalı devre soğutma kulesi</li><li>1 adet DCTP 12C — Çift hücreli kapalı devre soğutma kulesi</li><li>Toplam: 4 ünite</li><li>Lokasyon: Gebze, Kocaeli</li><li>Sektör: Endüstriyel Gaz / Kimya</li></ul><h3>TCTP 26B Modeli</h3><p>TCTP serisi, yüksek ısı atma kapasitesi gerektiren proses uygulamaları için tasarlanmış ters akışlı (counter-flow) kapalı devre soğutma kulesidir. FRP gövde yapısı ve yüksek verimli serpantin sistemi ile uzun ömürlü ve düşük bakım maliyetli çalışma imkânı sunar.</p>\",\"description\":\"Linde Gaz Gebze tesisi için 3×TCTP 26B + 1×DCTP 12C yüksek kapasiteli kapalı devre soğutma sistemi.\"}','Linde Gaz Gebze — TCTP 26B + DCTP 12C Su Soğutma Sistemi','Linde Gaz TCTP 26B DCTP 12C Kapalı Devre Soğutma — ENSOTEK Gebze','Linde Gaz Türkiye Gebze tesisi için ENSOTEK tarafından 3 adet TCTP 26B ve 1 adet DCTP 12C kapalı devre su soğutma sistemi kuruldu.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0006-4444-8444-444400000006','33333001-0006-4333-8333-333300000006','tr','HES Kablo — DCTP 12 ve DCTP 12C Kapalı Devre Su Soğutma Kulesi','hes-kablo-dctp-12-dctp-12c-kapali-devre-su-sogutma-kulesi','Kablo üretim sektörünün önde gelen firmalarından HES Kablo\'nun tesisi için DCTP 12 (merdiven aksesuarlı) ve DCTP 12C model kapalı devre su soğutma kuleleri devreye alındı.','{\"html\":\"<p><strong>HES Kablo</strong>\'nun üretim tesisine, proses soğutma ihtiyacını karşılamak üzere <strong>2 adet DCTP serisi Kapalı Devre Su Soğutma Kulesi</strong> temin edilmiştir.</p><h3>Sistem Özellikleri</h3><ul><li>DCTP 12 — Tek hücreli kapalı devre soğutma kulesi (servis merdiveni aksesuarlı)</li><li>DCTP 12C — Çift hücreli kapalı devre soğutma kulesi</li><li>Sektör: Kablo Üretimi / Elektrik</li><li>Özel: Bakım ve servis erişimi için özel merdiven aksesuarı</li></ul><p>Kablo üretiminde kullanılan proses ekipmanlarının soğutulması, ürün kalitesi açısından kritik öneme sahiptir. Kapalı devre sistemimiz, soğutma suyunun dış ortamla temasını engelleyerek kirlenme riskini sıfıra indirmektedir.</p>\",\"description\":\"HES Kablo üretim tesisi için DCTP 12 (merdiven aksesuarlı) ve DCTP 12C kapalı devre soğutma kulesi.\"}','HES Kablo — DCTP 12 + DCTP 12C Kapalı Devre Soğutma Kulesi','HES Kablo DCTP Kapalı Devre Su Soğutma Kulesi — ENSOTEK','HES Kablo üretim tesisi için ENSOTEK tarafından DCTP 12 ve DCTP 12C kapalı devre su soğutma kuleleri devreye alındı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0007-4444-8444-444400000007','33333001-0007-4333-8333-333300000007','tr','Green Park Oteli — 2 Adet CTP 3C Açık Tip Su Soğutma Kulesi','green-park-otel-ctp-3c-acik-tip-su-sogutma-kulesi','Green Park Oteller bünyesindeki otel tesisinin iklimlendirme sistemine 2 adet CTP 3C model açık tip su soğutma kulesi entegre edildi.','{\"html\":\"<p><strong>Green Park Hotels</strong> zincirindeki otel tesisi için <strong>2 adet CTP 3C model Açık Tip Su Soğutma Kulesi</strong> sistemi kurulmuştur.</p><h3>Proje Özellikleri</h3><ul><li>Model: CTP 3C (Açık Devre)</li><li>Adet: 2 ünite</li><li>Sektör: Otel / Konaklama / HVAC</li><li>Uygulama: Otel merkezi iklimlendirme soğutma sistemi</li></ul><h3>Otel Uygulamalarında CTP Serisi</h3><p>CTP serisi soğutma kuleleri; düşük gürültü seviyesi, kompakt boyutları ve estetik görünümleri ile otel ve konaklama işletmeleri için ideal çözüm sunar. Fiberglas gövde yapısı, bakım gereksinimini minimize ederek işletme maliyetlerini düşürür.</p>\",\"description\":\"Green Park Oteli iklimlendirme sistemine 2 adet CTP 3C açık tip su soğutma kulesi entegrasyonu.\"}','Green Park Otel — 2 Adet CTP 3C Su Soğutma Kulesi','Green Park Otel CTP 3C Açık Tip Su Soğutma Kulesi — ENSOTEK','Green Park Oteli için ENSOTEK tarafından 2 adet CTP 3C açık tip su soğutma kulesi kuruldu. HVAC otel soğutma sistemi.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0008-4444-8444-444400000008','33333001-0008-4333-8333-333300000008','tr','Orion AVM — TCTP 9C Kapalı Devre Su Soğutma Kulesi','orion-avm-tctp-9c-kapali-devre-su-sogutma-kulesi','Alışveriş merkezi uygulaması için TCTP 9C model kapalı devre su soğutma kulesi sistemi kuruldu.','{\"html\":\"<p><strong>Orion AVM</strong>\'nin merkezi iklimlendirme altyapısına <strong>TCTP 9C model Kapalı Devre Su Soğutma Kulesi</strong> entegre edilmiştir.</p><h3>Proje Özellikleri</h3><ul><li>Model: TCTP 9C (Ters Akışlı — Kapalı Devre)</li><li>Adet: 1 ünite</li><li>Sektör: Ticari / Alışveriş Merkezi</li><li>Uygulama: Merkezi soğutma sistemi (chiller soğutma suyu)</li></ul><p>Alışveriş merkezlerinde yıl boyu sürdürülebilir ve güvenilir soğutma kapasitesi sunmak için tasarlanan TCTP 9C, kompakt boyutları ve yüksek verimliliği ile öne çıkar.</p>\",\"description\":\"Orion AVM merkezi iklimlendirme sistemi için TCTP 9C kapalı devre su soğutma kulesi.\"}','Orion AVM — TCTP 9C Kapalı Devre Soğutma Kulesi','Orion AVM TCTP 9C Su Soğutma Kulesi — ENSOTEK','Orion AVM için ENSOTEK tarafından TCTP 9C kapalı devre su soğutma kulesi kuruldu.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0009-4444-8444-444400000009','33333001-0009-4333-8333-333300000009','tr','Plastifay — CTP 9 Açık Tip Su Soğutma Kulesi','plastifay-ctp-9-acik-tip-su-sogutma-kulesi','Plastik sektöründe faaliyet gösteren Plastifay\'ın üretim tesisi için CTP 9 model açık tip su soğutma kulesi sistemi devreye alındı.','{\"html\":\"<p><strong>Plastifay</strong>\'ın üretim tesisine proses soğutma ihtiyacı için <strong>CTP 9 model Açık Tip Su Soğutma Kulesi</strong> sistemi kurulmuştur.</p><h3>Proje Özellikleri</h3><ul><li>Model: CTP 9 (Açık Devre)</li><li>Sektör: Plastik / Kimya</li><li>Uygulama: Proses ekipmanı soğutma</li></ul><p>Plastik enjeksiyon ve ekstrüzyon makinelerinin soğutulmasında açık devre soğutma sistemi yaygın olarak tercih edilir. CTP 9 modeli, bu uygulamalar için optimize edilmiş kapasite ve verimlilik sunar.</p>\",\"description\":\"Plastifay üretim tesisi için CTP 9 açık tip su soğutma kulesi proje çözümü.\"}','Plastifay — CTP 9 Açık Tip Su Soğutma Kulesi','Plastifay CTP 9 Açık Tip Su Soğutma Kulesi — ENSOTEK','Plastifay plastik üretim tesisi için ENSOTEK CTP 9 açık tip su soğutma kulesi devreye alındı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0010-4444-8444-444400000010','33333001-0010-4333-8333-333300000010','tr','Aves Yağ — TCTP 9B + DCTP 9B Kombine Soğutma Sistemi — Mersin','aves-yag-tctp-9b-dctp-9b-kombine-sogutma-sistemi-mersin','Mersin\'de faaliyet gösteren Aves Yağ\'ın gıda üretim tesisi için TCTP 9B ve DCTP 9B model kapalı devre su soğutma kulesi kombine sistemi kuruldu.','{\"html\":\"<p><strong>Aves Yağ</strong>\'ın Mersin\'deki gıda üretim tesisi için <strong>TCTP 9B ve DCTP 9B model Kapalı Devre Su Soğutma Kulesi</strong> kombine sistemi devreye alınmıştır.</p><h3>Sistem Bileşenleri</h3><ul><li>1 adet TCTP 9B — Ters akışlı kapalı devre soğutma kulesi</li><li>1 adet DCTP 9B — Çift hücreli kapalı devre soğutma kulesi</li><li>Lokasyon: Mersin</li><li>Sektör: Gıda / Bitkisel Yağ Üretimi</li></ul><h3>Gıda Endüstrisinde Kapalı Devre Soğutma</h3><p>Gıda üretiminde hijyen ve ürün güvenliği en öncelikli unsurdur. Kapalı devre soğutma sistemi, süreç sıvısının dış etkenlerle temasını önleyerek hijyenik bir üretim ortamı sağlar. TCTP 9B ve DCTP 9B\'nin kombinasyonu, farklı kapasite ihtiyaçlarını dengeli şekilde karşılar.</p>\",\"description\":\"Aves Yağ Mersin gıda tesisi için TCTP 9B ve DCTP 9B kombine kapalı devre soğutma sistemi.\"}','Aves Yağ Mersin — TCTP 9B + DCTP 9B Kombine Soğutma Sistemi','Aves Yağ Mersin TCTP DCTP Kapalı Devre Su Soğutma — ENSOTEK','Aves Yağ Mersin gıda üretim tesisi için ENSOTEK TCTP 9B ve DCTP 9B kombine kapalı devre su soğutma kulesi sistemi devreye alındı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0011-4444-8444-444400000011','33333001-0011-4333-8333-333300000011','tr','TAT Tekstil — CTP Kaportalı Açık Tip Su Soğutma Kulesi — Gaziantep','tat-tekstil-ctp-kapotali-acik-tip-su-sogutma-kulesi-gaziantep','Gaziantep\'te faaliyet gösteren TAT Tekstil\'in üretim tesisi için CTP Kaportalı Açık Tip su soğutma kulesi sistemi kuruldu.','{\"html\":\"<p><strong>TAT Tekstil</strong>\'in Gaziantep\'teki üretim tesisine <strong>CTP Kaportalı Açık Tip Su Soğutma Kulesi</strong> sistemi temin edilmiştir.</p><h3>Proje Özellikleri</h3><ul><li>Lokasyon: Gaziantep</li><li>Sektör: Tekstil / İplik Üretimi</li><li>Uygulama: Tekstil makineleri proses soğutma</li></ul><h3>Tekstil Sektöründe Soğutma</h3><p>Tekstil üretiminde boya, yıkama ve dokuma makineleri yoğun ısı açığa çıkarır. CTP Kaportalı Açık Tip soğutma kulesi, bu uygulamalar için maliyet etkin ve verimli bir çözüm sunmaktadır.</p>\",\"description\":\"TAT Tekstil Gaziantep üretim tesisi için CTP Kaportalı Açık Tip su soğutma kulesi.\"}','TAT Tekstil Gaziantep — CTP Kaportalı Açık Tip Su Soğutma Kulesi','TAT Tekstil Gaziantep CTP Su Soğutma Kulesi — ENSOTEK','TAT Tekstil Gaziantep üretim tesisi için ENSOTEK CTP Kaportalı Açık Tip su soğutma kulesi devreye alındı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0012-4444-8444-444400000012','33333001-0012-4333-8333-333300000012','tr','Suudi Arabistan — Endüstriyel FRP Su Soğutma Kulesi İhracat Projesi','suudi-arabistan-endustriyel-frp-su-sogutma-kulesi-ihracat','Orta Doğu\'nun en büyük ekonomileri arasında yer alan Suudi Arabistan\'a endüstriyel FRP/GRP su soğutma kulesi ihracat projesi başarıyla gerçekleştirildi.','{\"html\":\"<p>ENSOTEK, Türkiye\'nin en büyük su soğutma kulesi üreticisi olarak, <strong>Suudi Arabistan</strong>\'a yönelik uluslararası ihracat projelerini de başarıyla hayata geçirmektedir.</p><h3>İhracat Projesi Detayları</h3><ul><li>Ülke: Suudi Arabistan</li><li>Ürün: FRP / GRP Açık Tip Su Soğutma Kulesi</li><li>Uygulama: Endüstriyel proses soğutma</li><li>Sektör: Petrokimya / Enerji / Sanayi</li></ul><h3>Sert İklim Koşullarına Uygunluk</h3><p>Suudi Arabistan\'ın yüksek çevre sıcaklığı ve zorlu iklim koşulları, soğutma kulesi seçiminde özel tasarım gerektirir. ENSOTEK\'in FRP/GRP gövde yapısı, güneş radyasyonuna ve yüksek ısıya karşı üstün dayanıklılık sunmaktadır.</p>\",\"description\":\"Suudi Arabistan endüstriyel FRP/GRP su soğutma kulesi ihracat projesi. ENSOTEK uluslararası referans.\"}','Suudi Arabistan — FRP GRP Su Soğutma Kulesi İhracat Projesi','Suudi Arabistan FRP Soğutma Kulesi İhracat — ENSOTEK Uluslararası','ENSOTEK tarafından Suudi Arabistan\'a endüstriyel FRP/GRP su soğutma kulesi ihracat projesi başarıyla tamamlandı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0013-4444-8444-444400000013','33333001-0013-4333-8333-333300000013','tr','İran — Endüstriyel FRP Su Soğutma Kulesi İhracat Projesi','iran-endustriyel-frp-su-sogutma-kulesi-ihracat','İran\'daki sanayi tesisi için FRP/GRP açık tip su soğutma kulesi ihracat projesi ENSOTEK tarafından başarıyla tamamlandı.','{\"html\":\"<p>ENSOTEK, Orta Doğu ve çevre bölgelerdeki uluslararası ihracat faaliyetleri kapsamında <strong>İran</strong>\'daki bir sanayi tesisi için su soğutma kulesi sistemi temin etmiştir.</p><h3>Proje Özellikleri</h3><ul><li>Ülke: İran</li><li>Ürün: FRP / GRP Açık Tip Su Soğutma Kulesi</li><li>Uygulama: Endüstriyel proses soğutma</li></ul><p>ENSOTEK, Türkiye pazarındaki 40 yılı aşkın deneyimini uluslararası projelere de taşıyarak, farklı coğrafyalardaki sanayi tesislerine güvenilir soğutma çözümleri sunmaktadır.</p>\",\"description\":\"İran sanayi tesisi için FRP/GRP açık tip su soğutma kulesi ihracat projesi. ENSOTEK uluslararası referans.\"}','İran — FRP GRP Su Soğutma Kulesi İhracat Projesi','İran FRP Su Soğutma Kulesi İhracat — ENSOTEK Uluslararası','ENSOTEK tarafından İran sanayi tesisine FRP/GRP açık tip su soğutma kulesi ihracat projesi tamamlandı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0014-4444-8444-444400000014','33333001-0014-4333-8333-333300000014','tr','Tüpraş İzmit Rafinerisi — Proses Soğutma Kulesi Sistemi','tupras-izmit-rafinerisi-proses-sogutma-kulesi','Türkiye\'nin en büyük petrol rafinerisi Tüpraş İzmit Rafinerisi\'ne yüksek kapasiteli proses soğutma kulesi sistemi temin edildi.','{\"html\":\"<p>Türkiye\'nin en büyük sanayi kuruluşlarından <strong>Tüpraş</strong>\'ın İzmit Rafinerisi\'ne yönelik <strong>proses soğutma kulesi sistemi</strong> ENSOTEK tarafından sağlanmıştır.</p><h3>Proje Detayları</h3><ul><li>Müşteri: Tüpraş (Türkiye Petrol Rafinerileri A.Ş.)</li><li>Lokasyon: İzmit, Kocaeli</li><li>Sektör: Petrokimya / Rafineri</li><li>Uygulama: Rafineri proses soğutma</li></ul><h3>Rafineri Uygulamalarında Soğutma</h3><p>Petrol rafinerilerinde distilasyon, kraking ve diğer proses ekipmanları yüksek ısı açığa çıkarır. ENSOTEK soğutma kuleleri, bu yüksek kapasiteli ısı atma uygulamalarında güvenilir ve verimli performans sunar. FRP/GRP malzeme yapısı, kimyasal ve korozif ortamlara karşı üstün dayanıklılık sağlar.</p>\",\"description\":\"Tüpraş İzmit Rafinerisi için ENSOTEK proses soğutma kulesi sistemi — petrokimya sektörü referans.\"}','Tüpraş İzmit Rafinerisi — Proses Soğutma Kulesi','Tüpraş İzmit Rafineri Proses Soğutma Kulesi — ENSOTEK','Tüpraş İzmit Rafinerisi için ENSOTEK tarafından yüksek kapasiteli proses soğutma kulesi sistemi temin edildi.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('44444001-0015-4444-8444-444400000015','33333001-0015-4333-8333-333300000015','tr','TOFAS Bursa Otomotiv Tesisi — CTP Kaportalı Açık Tip Su Soğutma Kulesi','tofas-bursa-otomotiv-tesisi-ctp-kapotali-acik-tip-su-sogutma-kulesi','Türkiye\'nin önde gelen otomobil üreticisi TOFAS\'ın Bursa\'daki otomotiv üretim tesisi için CTP Kaportalı Açık Tip su soğutma kulesi sistemi devreye alındı.','{\"html\":\"<p><strong>TOFAS</strong>\'ın Bursa\'daki geniş kapsamlı otomotiv üretim tesisi için <strong>CTP Kaportalı Açık Tip Su Soğutma Kulesi</strong> sistemi temin edilmiştir.</p><h3>Proje Detayları</h3><ul><li>Müşteri: TOFAS (Türk Otomobil Fabrikası A.Ş.)</li><li>Lokasyon: Bursa</li><li>Sektör: Otomotiv / Araç Üretimi</li><li>Uygulama: Boya hatları, kalıp ve proses ekipmanı soğutma</li></ul><h3>Otomotiv Sektöründe Soğutma</h3><p>Otomotiv fabrikalarında boya hatları, kaynak istasyonları ve kalıp soğutma sistemleri yüksek soğutma kapasitesi gerektirir. ENSOTEK\'in CTP Kaportalı açık tip soğutma kuleleri; yüksek debi kapasitesi, uzun ömür ve düşük bakım maliyeti ile bu talepleri karşılar.</p>\",\"description\":\"TOFAS Bursa otomotiv üretim tesisi için CTP Kaportalı Açık Tip su soğutma kulesi projesi.\"}','TOFAS Bursa — CTP Kaportalı Açık Tip Su Soğutma Kulesi','TOFAS Bursa Otomotiv Tesisi Su Soğutma Kulesi — ENSOTEK','TOFAS Bursa otomotiv üretim tesisi için ENSOTEK CTP Kaportalı Açık Tip su soğutma kulesi sistemi devreye alındı.','2026-03-23 04:11:30.689','2026-03-23 04:11:30.689'),('55555001-0001-4555-8555-555500000001','33333001-0001-4333-8333-333300000001','en','Istanbul High-Rise Plaza — 2× FRP-Canopy Open-Type Cooling Tower (130 m Rooftop)','istanbul-plaza-rooftop-frp-canopy-open-type-cooling-tower-130m','Two 2-fan FRP-canopy open-type cooling towers manufactured at ENSOTEK Istanbul Factory were successfully installed on the rooftop of a high-rise plaza building at 130 m elevation in Istanbul.','{\"html\":\"<p>Two <strong>FRP-canopy (CTP Kaportali) open-type cooling towers</strong>, each with 2 fans, manufactured at ENSOTEK\'s Istanbul Factory, were successfully installed on the rooftop of a high-rise commercial tower at <strong>130 m elevation</strong> in Istanbul.</p><h3>Project Specifications</h3><ul><li>Type: FRP-Canopy Open-Type Cooling Tower</li><li>Units: 2</li><li>Fans per unit: 2</li><li>Installation height: 130 m (rooftop)</li><li>Production plant: ENSOTEK Istanbul Factory</li></ul><p>The fiberglass-reinforced polyester (FRP) structure provides exceptional resistance to environmental conditions, ensuring reliable long-term performance even at extreme rooftop heights.</p>\",\"description\":\"Two 2-fan FRP-canopy open-type cooling towers installed on a 130m rooftop plaza in Istanbul.\"}','Istanbul Plaza Rooftop — FRP Canopy Open-Type Cooling Tower Installation','Istanbul Plaza Rooftop FRP Cooling Tower — ENSOTEK','Two 2-fan FRP-canopy open-type cooling towers installed at 130 m rooftop height in Istanbul. ENSOTEK Turkey cooling tower project.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0002-4555-8555-555500000002','33333001-0002-4333-8333-333300000002','en','Kahramanmaraş Industrial Facility — FRP-Canopy Open-Type Cooling Tower','kahramanmaras-industrial-frp-canopy-open-type-cooling-tower','FRP-canopy open-type cooling towers manufactured at ENSOTEK Ankara Factory were successfully delivered and commissioned at an industrial facility in Kahramanmaraş.','{\"html\":\"<p><strong>FRP-canopy open-type cooling towers</strong> produced at ENSOTEK\'s Ankara Factory have been successfully manufactured and commissioned at an industrial facility in <strong>Kahramanmaraş</strong>, Turkey.</p><h3>Project Details</h3><ul><li>Type: FRP-Canopy Open-Type Cooling Tower</li><li>Production plant: ENSOTEK Ankara Factory</li><li>Location: Kahramanmaraş, Turkey</li><li>Application: Industrial process cooling</li></ul><p>ENSOTEK\'s Ankara facility—Turkey\'s largest cooling tower production plant—handles FRP manufacturing, serpentine coil production, and full tower assembly in-house, ensuring the highest quality standards.</p>\",\"description\":\"FRP-canopy open-type cooling towers from Ankara Factory installed at Kahramanmaraş industrial facility.\"}','Kahramanmaraş — FRP Canopy Open-Type Cooling Tower','Kahramanmaraş Industrial Cooling Tower — ENSOTEK Ankara Factory','ENSOTEK Ankara Factory FRP-canopy open-type cooling towers delivered and commissioned at Kahramanmaraş industrial facility.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0003-4555-8555-555500000003','33333001-0003-4333-8333-333300000003','en','Arçelik — 2× CTP 6C Open-Type Cooling Towers','arcelik-ctp-6c-open-type-cooling-towers','Two CTP 6C open-type FRP cooling towers were supplied and commissioned for Arçelik\'s production facility in Gebze, Kocaeli.','{\"html\":\"<p>Two <strong>CTP 6C open-type FRP cooling towers</strong> were designed, manufactured, and commissioned for the production facility of <strong>Arçelik A.Ş.</strong>, one of Turkey\'s largest consumer electronics manufacturers.</p><h3>Project Details</h3><ul><li>Model: CTP 6C (Open Circuit)</li><li>Units: 2</li><li>Location: Gebze, Kocaeli</li><li>Sector: Consumer Electronics / Industrial Manufacturing</li></ul><h3>CTP 6C Specification</h3><p>The CTP 6C is a mid-to-large-capacity open-circuit cooling tower. Its FRP body provides superior resistance to corrosion, UV radiation, and chemical exposure, making it ideal for long-term industrial use.</p>\",\"description\":\"2× CTP 6C open-type FRP cooling towers for Arçelik production facility in Gebze, Kocaeli.\"}','Arçelik Facility — 2× CTP 6C Open-Type Cooling Towers','Arçelik CTP 6C Cooling Tower Project — ENSOTEK','Two CTP 6C open-type FRP cooling towers supplied by ENSOTEK for Arçelik production facility in Gebze, Kocaeli, Turkey.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0004-4555-8555-555500000004','33333001-0004-4333-8333-333300000004','en','Eczacıbaşı — 3× DCTP 5C Closed-Circuit Cooling Towers','eczacibasi-dctp-5c-closed-circuit-cooling-towers','Three DCTP 5C closed-circuit FRP cooling towers were installed for Eczacıbaşı\'s pharmaceutical and chemical manufacturing facility in Istanbul.','{\"html\":\"<p>Three <strong>DCTP 5C closed-circuit FRP cooling towers</strong> have been installed at a production facility belonging to <strong>Eczacıbaşı</strong>, one of Turkey\'s most established pharmaceutical and chemical groups.</p><h3>Project Details</h3><ul><li>Model: DCTP 5C (Closed Circuit)</li><li>Units: 3</li><li>Location: Istanbul</li><li>Sector: Pharmaceutical / Chemical</li></ul><h3>Why Closed Circuit for Pharma?</h3><p>In pharmaceutical and chemical manufacturing, isolating the process fluid from the external environment is critical. The DCTP 5C\'s coil-type heat exchanger ensures the process fluid never comes into contact with cooling water, maintaining product quality and hygiene standards.</p>\",\"description\":\"3× DCTP 5C closed-circuit FRP cooling towers for Eczacıbaşı pharmaceutical facility in Istanbul.\"}','Eczacıbaşı — 3× DCTP 5C Closed-Circuit Cooling Towers','Eczacıbaşı DCTP 5C Closed-Circuit Cooling Tower — ENSOTEK','Three DCTP 5C closed-circuit FRP cooling towers installed by ENSOTEK for Eczacıbaşı pharmaceutical facility in Istanbul.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0005-4555-8555-555500000005','33333001-0005-4333-8333-333300000005','en','Linde Gas — 3× TCTP 26B + 1× DCTP 12C High-Capacity Closed-Circuit Cooling System — Gebze','linde-gas-tctp-26b-dctp-12c-closed-circuit-cooling-system-gebze','A high-capacity closed-circuit cooling system comprising 3× TCTP 26B and 1× DCTP 12C cooling towers was installed for Linde Gas Turkey\'s process plant in Gebze, Kocaeli.','{\"html\":\"<p>A large-scale closed-circuit cooling system was installed for the process plant of <strong>Linde Gas Turkey</strong> in Gebze, Kocaeli. The system combines ENSOTEK\'s highest-capacity tower models to meet the facility\'s demanding cooling requirements.</p><h3>System Components</h3><ul><li>3× TCTP 26B — High-capacity counter-flow closed-circuit cooling tower</li><li>1× DCTP 12C — Double-cell closed-circuit cooling tower</li><li>Total units: 4</li><li>Location: Gebze, Kocaeli</li><li>Sector: Industrial Gases / Chemistry</li></ul><h3>TCTP 26B Overview</h3><p>The TCTP series is designed for high-heat-rejection process applications using a counter-flow design. The FRP enclosure and high-efficiency coil heat exchanger system deliver long service life with minimal maintenance requirements.</p>\",\"description\":\"3× TCTP 26B + 1× DCTP 12C high-capacity closed-circuit cooling system for Linde Gas Turkey in Gebze.\"}','Linde Gas Gebze — TCTP 26B + DCTP 12C Cooling System','Linde Gas TCTP 26B DCTP 12C Closed-Circuit Cooling Tower — ENSOTEK Gebze','High-capacity 3× TCTP 26B and 1× DCTP 12C closed-circuit cooling system installed by ENSOTEK for Linde Gas Turkey in Gebze, Kocaeli.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0006-4555-8555-555500000006','33333001-0006-4333-8333-333300000006','en','HES Kablo — DCTP 12 + DCTP 12C Closed-Circuit Cooling Towers','hes-kablo-dctp-12-dctp-12c-closed-circuit-cooling-towers','A DCTP 12 (with service ladder accessory) and DCTP 12C closed-circuit cooling tower system was commissioned for HES Kablo\'s cable manufacturing facility.','{\"html\":\"<p>Two <strong>DCTP series closed-circuit cooling towers</strong> were supplied for the cable manufacturing facility of <strong>HES Kablo</strong>.</p><h3>System Details</h3><ul><li>DCTP 12 — Single-cell closed-circuit cooling tower (with service ladder accessory)</li><li>DCTP 12C — Double-cell closed-circuit cooling tower</li><li>Sector: Cable Manufacturing / Electrical</li><li>Special feature: Custom service ladder accessory for maintenance access</li></ul><p>In cable manufacturing, cooling of drawing and extrusion equipment is critical for product quality. The closed-circuit system prevents cooling water contamination, ensuring a clean and controlled production environment.</p>\",\"description\":\"DCTP 12 (with service ladder) + DCTP 12C closed-circuit cooling towers for HES Kablo cable facility.\"}','HES Kablo — DCTP 12 + DCTP 12C Closed-Circuit Cooling Tower','HES Kablo DCTP Closed-Circuit Cooling Tower — ENSOTEK','DCTP 12 and DCTP 12C closed-circuit cooling towers commissioned by ENSOTEK for HES Kablo cable manufacturing facility.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0007-4555-8555-555500000007','33333001-0007-4333-8333-333300000007','en','Green Park Hotel — 2× CTP 3C Open-Type Cooling Towers','green-park-hotel-ctp-3c-open-type-cooling-towers','Two CTP 3C open-type FRP cooling towers were integrated into the central HVAC cooling system at a Green Park Hotels property.','{\"html\":\"<p>Two <strong>CTP 3C open-type FRP cooling towers</strong> have been integrated into the central air-conditioning system of a <strong>Green Park Hotels</strong> property.</p><h3>Project Details</h3><ul><li>Model: CTP 3C (Open Circuit)</li><li>Units: 2</li><li>Sector: Hotel / Hospitality / HVAC</li><li>Application: Central chiller cooling water system</li></ul><h3>CTP Series for Hospitality</h3><p>ENSOTEK\'s CTP series cooling towers offer low noise levels, compact dimensions, and an aesthetic appearance—ideal for hotel and hospitality applications. The FRP body minimizes maintenance requirements, reducing operating costs over the tower\'s lifetime.</p>\",\"description\":\"2× CTP 3C open-type cooling towers integrated into the HVAC system at a Green Park Hotels property.\"}','Green Park Hotel — 2× CTP 3C Open-Type Cooling Towers','Green Park Hotel CTP 3C Cooling Tower — ENSOTEK HVAC','Two CTP 3C open-type FRP cooling towers installed by ENSOTEK for Green Park Hotels HVAC cooling system.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0008-4555-8555-555500000008','33333001-0008-4333-8333-333300000008','en','Orion Shopping Mall — TCTP 9C Closed-Circuit Cooling Tower','orion-shopping-mall-tctp-9c-closed-circuit-cooling-tower','A TCTP 9C closed-circuit cooling tower was installed for the central HVAC cooling system of Orion Shopping Mall.','{\"html\":\"<p>A <strong>TCTP 9C closed-circuit cooling tower</strong> was integrated into the central HVAC infrastructure of <strong>Orion Shopping Mall</strong>.</p><h3>Project Details</h3><ul><li>Model: TCTP 9C (Counter-flow — Closed Circuit)</li><li>Units: 1</li><li>Sector: Commercial / Shopping Mall</li><li>Application: Central chiller cooling water (year-round)</li></ul><p>The TCTP 9C\'s compact footprint and reliable performance make it well-suited for commercial buildings requiring year-round cooling capacity. ENSOTEK\'s FRP construction ensures long operational life with minimal maintenance intervention.</p>\",\"description\":\"TCTP 9C closed-circuit cooling tower for Orion Shopping Mall central HVAC cooling system.\"}','Orion Shopping Mall — TCTP 9C Closed-Circuit Cooling Tower','Orion Shopping Mall TCTP 9C Cooling Tower — ENSOTEK','TCTP 9C closed-circuit cooling tower installed by ENSOTEK for Orion Shopping Mall HVAC system.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0009-4555-8555-555500000009','33333001-0009-4333-8333-333300000009','en','Plastifay — CTP 9 Open-Type Cooling Tower','plastifay-ctp-9-open-type-cooling-tower','A CTP 9 open-type FRP cooling tower was commissioned for Plastifay\'s plastics manufacturing facility.','{\"html\":\"<p>A <strong>CTP 9 open-type FRP cooling tower</strong> was installed at <strong>Plastifay</strong>\'s production facility to meet its process cooling requirements.</p><h3>Project Details</h3><ul><li>Model: CTP 9 (Open Circuit)</li><li>Sector: Plastics / Chemicals</li><li>Application: Process equipment cooling (injection moulding / extrusion)</li></ul><p>Open-circuit cooling towers are widely used for cooling injection moulding and extrusion machinery in the plastics industry. The CTP 9 model offers optimised capacity and efficiency for these applications.</p>\",\"description\":\"CTP 9 open-type FRP cooling tower for Plastifay plastics manufacturing facility.\"}','Plastifay — CTP 9 Open-Type Cooling Tower','Plastifay CTP 9 Open-Type Cooling Tower — ENSOTEK','CTP 9 open-type FRP cooling tower commissioned by ENSOTEK for Plastifay plastics production facility.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0010-4555-8555-555500000010','33333001-0010-4333-8333-333300000010','en','Aves Yağ — TCTP 9B + DCTP 9B Combined Closed-Circuit Cooling System — Mersin','aves-yag-tctp-9b-dctp-9b-combined-cooling-system-mersin','A combined closed-circuit cooling system comprising a TCTP 9B and DCTP 9B was installed for Aves Yağ\'s edible oil production facility in Mersin.','{\"html\":\"<p>A combined closed-circuit cooling system was commissioned for <strong>Aves Yağ</strong>\'s edible oil production facility in <strong>Mersin</strong>, Turkey.</p><h3>System Components</h3><ul><li>1× TCTP 9B — Counter-flow closed-circuit cooling tower</li><li>1× DCTP 9B — Double-cell closed-circuit cooling tower</li><li>Location: Mersin, Turkey</li><li>Sector: Food & Beverage / Edible Oil Production</li></ul><h3>Closed-Circuit Cooling for Food Industry</h3><p>Hygiene and product safety are the top priorities in food production. A closed-circuit cooling system prevents process fluid from being exposed to external contaminants. The TCTP 9B and DCTP 9B combination provides balanced coverage of varying capacity demands at the facility.</p>\",\"description\":\"TCTP 9B + DCTP 9B combined closed-circuit cooling system for Aves Yağ edible oil facility in Mersin.\"}','Aves Yağ Mersin — TCTP 9B + DCTP 9B Combined Cooling System','Aves Yağ Mersin TCTP DCTP Closed-Circuit Cooling — ENSOTEK','TCTP 9B and DCTP 9B combined closed-circuit cooling system installed by ENSOTEK for Aves Yağ edible oil facility in Mersin.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0011-4555-8555-555500000011','33333001-0011-4333-8333-333300000011','en','TAT Tekstil — FRP-Canopy Open-Type Cooling Tower — Gaziantep','tat-tekstil-frp-canopy-open-type-cooling-tower-gaziantep','An FRP-canopy open-type cooling tower system was installed for TAT Tekstil\'s textile manufacturing facility in Gaziantep.','{\"html\":\"<p>An <strong>FRP-canopy open-type cooling tower</strong> system was supplied for <strong>TAT Tekstil</strong>\'s production facility in <strong>Gaziantep</strong>, Turkey.</p><h3>Project Details</h3><ul><li>Location: Gaziantep, Turkey</li><li>Sector: Textile / Yarn Manufacturing</li><li>Application: Textile machinery process cooling</li></ul><h3>Cooling in Textile Industry</h3><p>Textile production processes—including dyeing, washing, and weaving—generate significant heat loads. ENSOTEK\'s FRP-canopy open-type cooling towers provide a cost-effective and efficient solution for these demanding industrial applications.</p>\",\"description\":\"FRP-canopy open-type cooling tower for TAT Tekstil textile manufacturing facility in Gaziantep.\"}','TAT Tekstil Gaziantep — FRP Canopy Open-Type Cooling Tower','TAT Tekstil Gaziantep Cooling Tower — ENSOTEK','FRP-canopy open-type cooling tower installed by ENSOTEK for TAT Tekstil textile facility in Gaziantep, Turkey.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0012-4555-8555-555500000012','33333001-0012-4333-8333-333300000012','en','Saudi Arabia — Industrial FRP Cooling Tower Export Project','saudi-arabia-industrial-frp-cooling-tower-export','ENSOTEK successfully completed an industrial FRP/GRP cooling tower export project to Saudi Arabia, one of the largest economies in the Middle East.','{\"html\":\"<p>ENSOTEK, as Turkey\'s largest cooling tower manufacturer, has successfully delivered an <strong>industrial FRP/GRP cooling tower</strong> system to <strong>Saudi Arabia</strong> as part of its international export activities.</p><h3>Export Project Details</h3><ul><li>Country: Saudi Arabia</li><li>Product: FRP / GRP Open-Type Cooling Tower</li><li>Application: Industrial process cooling</li><li>Sector: Petrochemical / Energy / Industrial</li></ul><h3>Performance in Extreme Climates</h3><p>Saudi Arabia\'s high ambient temperatures and harsh climate demand special design considerations for cooling towers. ENSOTEK\'s FRP/GRP body construction offers superior resistance to solar radiation and extreme heat, ensuring reliable performance even in desert conditions.</p>\",\"description\":\"Industrial FRP/GRP cooling tower export project to Saudi Arabia. ENSOTEK international reference.\"}','Saudi Arabia — Industrial FRP GRP Cooling Tower Export','Saudi Arabia FRP Cooling Tower Export — ENSOTEK International','ENSOTEK successfully delivered an industrial FRP/GRP cooling tower to Saudi Arabia. International export project.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0013-4555-8555-555500000013','33333001-0013-4333-8333-333300000013','en','Iran — Industrial FRP Cooling Tower Export Project','iran-industrial-frp-cooling-tower-export','ENSOTEK successfully completed an FRP/GRP open-type cooling tower export project for an industrial facility in Iran.','{\"html\":\"<p>ENSOTEK has successfully supplied an <strong>FRP/GRP open-type cooling tower</strong> system to an industrial facility in <strong>Iran</strong> as part of its regional export programme.</p><h3>Project Details</h3><ul><li>Country: Iran</li><li>Product: FRP / GRP Open-Type Cooling Tower</li><li>Application: Industrial process cooling</li></ul><p>ENSOTEK leverages its 40+ years of experience in the Turkish market to deliver reliable cooling solutions to international markets across the Middle East and beyond.</p>\",\"description\":\"FRP/GRP open-type cooling tower export project for industrial facility in Iran. ENSOTEK international reference.\"}','Iran — Industrial FRP GRP Cooling Tower Export','Iran FRP Cooling Tower Export — ENSOTEK International','ENSOTEK successfully exported FRP/GRP open-type cooling towers to an industrial facility in Iran.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0014-4555-8555-555500000014','33333001-0014-4333-8333-333300000014','en','Tüpraş İzmit Refinery — Process Cooling Tower System','tupras-izmit-refinery-process-cooling-tower','A high-capacity process cooling tower system was supplied for Tüpraş İzmit Refinery, Turkey\'s largest oil refinery.','{\"html\":\"<p>A <strong>process cooling tower system</strong> was supplied by ENSOTEK for the <strong>Tüpraş İzmit Refinery</strong>, operated by Türkiye Petrol Rafinerileri A.Ş.—Turkey\'s largest industrial enterprise.</p><h3>Project Details</h3><ul><li>Client: Tüpraş (Türkiye Petrol Rafinerileri A.Ş.)</li><li>Location: İzmit, Kocaeli</li><li>Sector: Petrochemical / Oil Refining</li><li>Application: Refinery process cooling</li></ul><h3>Cooling in Oil Refining</h3><p>Oil refineries—including distillation, cracking, and other process units—generate extreme heat loads that require large-capacity cooling systems. ENSOTEK cooling towers provide reliable, high-capacity heat rejection for these demanding applications. The FRP/GRP material offers outstanding resistance to chemical and corrosive environments typical of refinery operations.</p>\",\"description\":\"High-capacity process cooling tower system for Tüpraş İzmit Refinery — petrochemical sector reference.\"}','Tüpraş İzmit Refinery — Process Cooling Tower System','Tüpraş İzmit Refinery Cooling Tower — ENSOTEK','High-capacity process cooling tower system supplied by ENSOTEK for Tüpraş İzmit Refinery, Turkey\'s largest oil refinery.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('55555001-0015-4555-8555-555500000015','33333001-0015-4333-8333-333300000015','en','TOFAS Bursa Automotive Plant — FRP-Canopy Open-Type Cooling Tower','tofas-bursa-automotive-plant-frp-canopy-open-type-cooling-tower','An FRP-canopy open-type cooling tower system was commissioned for TOFAS\'s automotive manufacturing plant in Bursa, one of Turkey\'s major vehicle production hubs.','{\"html\":\"<p>An <strong>FRP-canopy open-type cooling tower</strong> system was supplied for <strong>TOFAS</strong>\'s (Türk Otomobil Fabrikası A.Ş.) large-scale automotive manufacturing plant in <strong>Bursa</strong>.</p><h3>Project Details</h3><ul><li>Client: TOFAS (Türk Otomobil Fabrikası A.Ş.)</li><li>Location: Bursa, Turkey</li><li>Sector: Automotive / Vehicle Manufacturing</li><li>Application: Paint lines, mould cooling, and process equipment cooling</li></ul><h3>Cooling in Automotive Manufacturing</h3><p>Automotive plants—including paint lines, welding stations, and mould-cooling systems—require high-volume cooling capacity. ENSOTEK\'s FRP-canopy open-type cooling towers provide high flow capacity, long service life, and low maintenance costs to meet these requirements.</p>\",\"description\":\"FRP-canopy open-type cooling tower for TOFAS Bursa automotive manufacturing plant.\"}','TOFAS Bursa Automotive Plant — FRP Canopy Open-Type Cooling Tower','TOFAS Bursa Automotive Plant Cooling Tower — ENSOTEK','FRP-canopy open-type cooling tower system supplied by ENSOTEK for TOFAS automotive manufacturing plant in Bursa, Turkey.','2026-03-23 04:11:30.678','2026-03-23 04:11:30.678'),('66666001-0001-4666-8666-666600000001','33333001-0001-4333-8333-333300000001','de','Istanbul Hochhaus-Plaza — 2× FRP-Kühlturm (Offener Kreislauf, Dachmontage 130 m)','istanbul-hochhaus-plaza-frp-kuehlturm-offener-kreislauf-130m','Zwei offene FRP-Kühltürme mit Schutzdach (je 2 Ventilatoren), gefertigt im ENSOTEK-Werk Istanbul, wurden erfolgreich auf dem 130 Meter hohen Dach eines Hochhauses in Istanbul installiert.','{\"html\":\"<p>Zwei <strong>FRP-Kühltürme (CTP-Kaportali, offener Kreislauf)</strong> mit je 2 Ventilatoren, produziert im ENSOTEK-Werk Istanbul, wurden erfolgreich auf dem Dach eines kommerziellen Hochhauses in <strong>Istanbul in 130 Meter Höhe</strong> montiert.</p><h3>Projektdaten</h3><ul><li>Typ: Offener Kühlturm mit FRP-Schutzdach</li><li>Anzahl: 2 Einheiten</li><li>Ventilatoren je Einheit: 2</li><li>Montagehöhe: 130 m (Dachmontage)</li><li>Produktionsstandort: ENSOTEK-Werk Istanbul</li></ul><p>Die Konstruktion aus glasfaserverstärktem Polyester (GFK/FRP) gewährleistet hervorragende Beständigkeit gegenüber Umwelteinflüssen und ermöglicht einen zuverlässigen Langzeitbetrieb selbst auf extremen Dachhöhen.</p>\",\"description\":\"Zwei FRP-Kühltürme (offener Kreislauf, je 2 Ventilatoren) auf einem 130 m hohen Plaza-Dach in Istanbul montiert.\"}','Istanbul Hochhaus-Plaza — FRP-Kühlturm Dachmontage 130 m','Istanbul Plaza Dach FRP-Kühlturm 130 m — ENSOTEK','Zwei offene FRP-Kühltürme mit je 2 Ventilatoren auf einem 130 m hohen Hochhausdach in Istanbul installiert. ENSOTEK Türkei Kühlturmprojekt.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0002-4666-8666-666600000002','33333001-0002-4333-8333-333300000002','de','Kahramanmaraş Industrieanlage — FRP-Kühlturm mit Schutzdach (Offener Kreislauf)','kahramanmaras-industrieanlage-frp-kuehlturm-offener-kreislauf','Im ENSOTEK-Werk Ankara gefertigte FRP-Kühltürme mit Schutzdach wurden erfolgreich an eine Industrieanlage in Kahramanmaraş geliefert und in Betrieb genommen.','{\"html\":\"<p>Im ENSOTEK-Werk <strong>Ankara</strong> — dem größten Kühlturmproduktionswerk der Türkei — gefertigte <strong>FRP-Kühltürme mit Schutzdach (offener Kreislauf)</strong> wurden erfolgreich an eine Industrieanlage in <strong>Kahramanmaraş</strong> geliefert und in Betrieb genommen.</p><h3>Projektdetails</h3><ul><li>Typ: Offener Kühlturm mit FRP-Schutzdach</li><li>Produktionsstandort: ENSOTEK-Werk Ankara</li><li>Standort: Kahramanmaraş, Türkei</li><li>Anwendung: Industrielle Prozesskühlung</li></ul><p>Das ENSOTEK-Werk Ankara umfasst die gesamte Wertschöpfungskette: GFK-Fertigung, Schlangenwärmetauscherfertigung und Komplettmontage — alles aus einer Hand.</p>\",\"description\":\"Im ENSOTEK-Werk Ankara gefertigte FRP-Kühltürme für Industrieanlage in Kahramanmaraş.\"}','Kahramanmaraş — FRP-Kühlturm mit Schutzdach (Offener Kreislauf)','Kahramanmaraş Industriekühlturm — ENSOTEK Werk Ankara','ENSOTEK Werk Ankara FRP-Kühltürme für Industrieanlage in Kahramanmaraş geliefert und in Betrieb genommen.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0003-4666-8666-666600000003','33333001-0003-4333-8333-333300000003','de','Arçelik — 2× CTP 6C Offene Kühltürme','arcelik-ctp-6c-offene-kuehlturme','Zwei offene GFK-Kühltürme vom Typ CTP 6C wurden für das Produktionswerk von Arçelik A.Ş. in Gebze, Kocaeli, geliefert und in Betrieb genommen.','{\"html\":\"<p>Zwei <strong>CTP 6C offene GFK-Kühltürme</strong> wurden für das Produktionswerk von <strong>Arçelik A.Ş.</strong> — einem der größten Konsumgüter- und Elektronikhersteller der Türkei — entworfen, gefertigt und in Betrieb genommen.</p><h3>Projektdaten</h3><ul><li>Modell: CTP 6C (Offener Kreislauf)</li><li>Anzahl: 2 Einheiten</li><li>Standort: Gebze, Kocaeli</li><li>Branche: Konsumgüter / Elektronikfertigung</li></ul><p>Der GFK-Korpus des CTP 6C bietet hervorragenden Schutz gegen Korrosion, UV-Strahlung und chemische Einflüsse — ideal für den langfristigen Industrieeinsatz.</p>\",\"description\":\"2× CTP 6C offene GFK-Kühltürme für Arçelik-Produktionswerk in Gebze, Kocaeli.\"}','Arçelik — 2× CTP 6C Offene GFK-Kühltürme','Arçelik CTP 6C Kühlturm — ENSOTEK','Zwei CTP 6C offene GFK-Kühltürme von ENSOTEK für Arçelik-Produktionswerk in Gebze, Kocaeli, Türkei.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0004-4666-8666-666600000004','33333001-0004-4333-8333-333300000004','de','Eczacıbaşı — 3× DCTP 5C Geschlossene Kreislauf-Kühltürme','eczacibasi-dctp-5c-geschlossene-kreislauf-kuehlturme','Drei geschlossene GFK-Kühltürme vom Typ DCTP 5C wurden für eine Produktionsanlage von Eczacıbaşı in Istanbul installiert.','{\"html\":\"<p>Drei <strong>DCTP 5C geschlossene Kreislauf-GFK-Kühltürme</strong> wurden für eine Produktionsanlage der <strong>Eczacıbaşı</strong>-Gruppe — einem der bedeutendsten Pharma- und Chemiekonzerne der Türkei — in Istanbul installiert.</p><h3>Projektdetails</h3><ul><li>Modell: DCTP 5C (Geschlossener Kreislauf)</li><li>Anzahl: 3 Einheiten</li><li>Standort: Istanbul</li><li>Branche: Pharmazeutik / Chemie</li></ul><h3>Warum geschlossener Kreislauf in der Pharmaindustrie?</h3><p>In der pharmazeutischen und chemischen Produktion ist die Isolierung der Prozessflüssigkeit von der Außenumgebung entscheidend. Der Schlangenwärmetauscher des DCTP 5C verhindert jeden Kontakt zwischen Prozessflüssigkeit und Kühlwasser — Produktqualität und Hygiene bleiben gewährleistet.</p>\",\"description\":\"3× DCTP 5C geschlossene GFK-Kühltürme für Eczacıbaşı Pharmaanlage in Istanbul.\"}','Eczacıbaşı — 3× DCTP 5C Geschlossene GFK-Kühltürme','Eczacıbaşı DCTP 5C Geschlossener Kreislauf Kühlturm — ENSOTEK','Drei DCTP 5C geschlossene GFK-Kühltürme von ENSOTEK für Eczacıbaşı Pharmaanlage in Istanbul installiert.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0005-4666-8666-666600000005','33333001-0005-4333-8333-333300000005','de','Linde Gas — 3× TCTP 26B + 1× DCTP 12C Hochleistungs-Kühlsystem — Gebze','linde-gas-tctp-26b-dctp-12c-hochleistungs-kuehlsystem-gebze','Ein Hochleistungs-Kühlsystem mit 3× TCTP 26B und 1× DCTP 12C wurde für das Prozesswerk von Linde Gas Türkiye in Gebze, Kocaeli, installiert.','{\"html\":\"<p>Für das Prozesswerk von <strong>Linde Gas Türkiye</strong> in Gebze wurde ein großes geschlossenes Kreislauf-Kühlsystem mit den leistungsstärksten ENSOTEK-Modellen installiert.</p><h3>Systemkomponenten</h3><ul><li>3× TCTP 26B — Hochleistungs-Gegenstrom-Kühlturm (geschlossener Kreislauf)</li><li>1× DCTP 12C — Doppelzellen-Kühlturm (geschlossener Kreislauf)</li><li>Gesamt: 4 Einheiten</li><li>Standort: Gebze, Kocaeli</li><li>Branche: Industriegase / Chemie</li></ul><h3>TCTP 26B im Überblick</h3><p>Die TCTP-Serie ist für anspruchsvolle Prozessanwendungen mit hohem Wärmeabfuhrbedarf im Gegenstromverfahren konzipiert. GFK-Gehäuse und hocheffizienter Schlangenwärmetauscher gewährleisten lange Betriebsdauer bei minimalem Wartungsaufwand.</p>\",\"description\":\"3× TCTP 26B + 1× DCTP 12C Hochleistungs-Kühlsystem für Linde Gas Türkiye in Gebze.\"}','Linde Gas Gebze — TCTP 26B + DCTP 12C Hochleistungs-Kühlsystem','Linde Gas TCTP 26B DCTP 12C Kühlturm — ENSOTEK Gebze','Hochleistungs-Kühlsystem 3× TCTP 26B + 1× DCTP 12C von ENSOTEK für Linde Gas Türkiye in Gebze, Kocaeli.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0006-4666-8666-666600000006','33333001-0006-4333-8333-333300000006','de','HES Kablo — DCTP 12 + DCTP 12C Geschlossene Kreislauf-Kühltürme','hes-kablo-dctp-12-dctp-12c-geschlossene-kreislauf-kuehlturme','Ein DCTP 12 (mit Serviceleiter-Zubehör) und ein DCTP 12C geschlossener Kreislauf-Kühlturm wurden für das Kabelfertigungswerk von HES Kablo in Betrieb genommen.','{\"html\":\"<p>Für das Kabelfertigungswerk von <strong>HES Kablo</strong> wurden zwei <strong>DCTP-Kühltürme im geschlossenen Kreislauf</strong> geliefert.</p><h3>Systemdetails</h3><ul><li>DCTP 12 — Einzelliger Kühlturm, geschlossener Kreislauf (mit Serviceleiter-Zubehör)</li><li>DCTP 12C — Doppelzelliger Kühlturm, geschlossener Kreislauf</li><li>Branche: Kabelherstellung / Elektrotechnik</li><li>Besonderheit: Maßgefertigtes Serviceleiter-Zubehör für optimalen Wartungszugang</li></ul><p>In der Kabelproduktion ist die Kühlung von Zieh- und Extrusionsmaschinen entscheidend für die Produktqualität. Das geschlossene Kreislaufsystem verhindert Kühlwasserkontaminierung und schafft eine saubere, kontrollierte Produktionsumgebung.</p>\",\"description\":\"DCTP 12 + DCTP 12C geschlossene Kreislauf-Kühltürme für HES Kablo Kabelfertigungswerk.\"}','HES Kablo — DCTP 12 + DCTP 12C Geschlossener Kreislauf-Kühlturm','HES Kablo DCTP Kühlturm — ENSOTEK','DCTP 12 und DCTP 12C geschlossene Kreislauf-Kühltürme von ENSOTEK für HES Kablo Kabelfertigungswerk in Betrieb genommen.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0007-4666-8666-666600000007','33333001-0007-4333-8333-333300000007','de','Green Park Hotel — 2× CTP 3C Offene GFK-Kühltürme','green-park-hotel-ctp-3c-offene-gfk-kuehlturme','Zwei offene GFK-Kühltürme vom Typ CTP 3C wurden in das zentrale Klimakühlsystem eines Green Park Hotels integriert.','{\"html\":\"<p>Zwei <strong>CTP 3C offene GFK-Kühltürme</strong> wurden in die zentrale Klimaanlage eines <strong>Green Park Hotels</strong> integriert.</p><h3>Projektdetails</h3><ul><li>Modell: CTP 3C (Offener Kreislauf)</li><li>Anzahl: 2 Einheiten</li><li>Branche: Hotel / Hospitality / HLK</li><li>Anwendung: Zentrale Kälteanlagen-Rückkühlung</li></ul><h3>CTP-Serie für Hotels</h3><p>ENSOTEK CTP-Kühltürme zeichnen sich durch niedrige Geräuschpegel, kompakte Abmessungen und ein ästhetisches Erscheinungsbild aus — ideal für Hotelbetriebe. Der GFK-Korpus minimiert den Wartungsaufwand und senkt die Betriebskosten über die gesamte Lebensdauer.</p>\",\"description\":\"2× CTP 3C offene GFK-Kühltürme im HLK-System eines Green Park Hotels integriert.\"}','Green Park Hotel — 2× CTP 3C Offene GFK-Kühltürme','Green Park Hotel CTP 3C Kühlturm — ENSOTEK HLK','Zwei CTP 3C offene GFK-Kühltürme von ENSOTEK für Green Park Hotel HLK-Kühlsystem installiert.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0008-4666-8666-666600000008','33333001-0008-4333-8333-333300000008','de','Orion Einkaufszentrum — TCTP 9C Geschlossener Kreislauf-Kühlturm','orion-einkaufszentrum-tctp-9c-geschlossener-kreislauf-kuehlturm','Ein TCTP 9C Gegenstrom-Kühlturm (geschlossener Kreislauf) wurde für das zentrale HLK-System des Orion Einkaufszentrums installiert.','{\"html\":\"<p>Ein <strong>TCTP 9C Kühlturm im geschlossenen Kreislauf</strong> wurde in die zentrale HLK-Infrastruktur des <strong>Orion Einkaufszentrums</strong> integriert.</p><h3>Projektdetails</h3><ul><li>Modell: TCTP 9C (Gegenstrom — geschlossener Kreislauf)</li><li>Anzahl: 1 Einheit</li><li>Branche: Einzelhandel / Einkaufszentrum</li><li>Anwendung: Zentrale Kälteanlagen-Rückkühlung (ganzjährig)</li></ul><p>Der kompakte Stellbedarf und die zuverlässige Leistung des TCTP 9C machen ihn ideal für Handels- und Gewerbegebäude mit ganzjährigem Kühlbedarf. Die GFK-Konstruktion von ENSOTEK garantiert lange Betriebsdauer bei minimalem Wartungsaufwand.</p>\",\"description\":\"TCTP 9C geschlossener Kreislauf-Kühlturm für zentrale HLK-Rückkühlung im Orion Einkaufszentrum.\"}','Orion Einkaufszentrum — TCTP 9C Geschlossener Kreislauf-Kühlturm','Orion Einkaufszentrum TCTP 9C Kühlturm — ENSOTEK','TCTP 9C geschlossener Kreislauf-Kühlturm von ENSOTEK für Orion Einkaufszentrum HLK-System installiert.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0009-4666-8666-666600000009','33333001-0009-4333-8333-333300000009','de','Plastifay — CTP 9 Offener GFK-Kühlturm','plastifay-ctp-9-offener-gfk-kuehlturm','Ein CTP 9 offener GFK-Kühlturm wurde für das Kunststoffproduktionswerk von Plastifay in Betrieb genommen.','{\"html\":\"<p>Ein <strong>CTP 9 offener GFK-Kühlturm</strong> wurde für das Produktionswerk von <strong>Plastifay</strong> installiert, um den Prozesskühlbedarf zu decken.</p><h3>Projektdetails</h3><ul><li>Modell: CTP 9 (Offener Kreislauf)</li><li>Branche: Kunststoff / Chemie</li><li>Anwendung: Prozesskühlung (Spritzguss / Extrusion)</li></ul><p>In der Kunststoffverarbeitung werden offene Kreislauf-Kühltürme bevorzugt für die Kühlung von Spritzguss- und Extrusionsmaschinen eingesetzt. Das CTP 9 Modell bietet optimierte Kapazität und Effizienz für diese Anwendungen.</p>\",\"description\":\"CTP 9 offener GFK-Kühlturm für Plastifay Kunststoffproduktionswerk.\"}','Plastifay — CTP 9 Offener GFK-Kühlturm','Plastifay CTP 9 Offener Kühlturm — ENSOTEK','CTP 9 offener GFK-Kühlturm von ENSOTEK für Plastifay Kunststoffproduktionswerk in Betrieb genommen.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0010-4666-8666-666600000010','33333001-0010-4333-8333-333300000010','de','Aves Yağ — TCTP 9B + DCTP 9B Kombiniertes Kühlsystem — Mersin','aves-yag-tctp-9b-dctp-9b-kombiniertes-kuehlsystem-mersin','Ein kombiniertes geschlossenes Kreislauf-Kühlsystem aus TCTP 9B und DCTP 9B wurde für das Speiseölproduktionswerk von Aves Yağ in Mersin installiert.','{\"html\":\"<p>Ein kombiniertes geschlossenes Kreislauf-Kühlsystem wurde für das Speiseöl-Produktionswerk von <strong>Aves Yağ</strong> in <strong>Mersin</strong> in Betrieb genommen.</p><h3>Systemkomponenten</h3><ul><li>1× TCTP 9B — Gegenstrom-Kühlturm (geschlossener Kreislauf)</li><li>1× DCTP 9B — Doppelzelliger Kühlturm (geschlossener Kreislauf)</li><li>Standort: Mersin, Türkei</li><li>Branche: Lebensmittel / Speiseölproduktion</li></ul><h3>Geschlossener Kreislauf in der Lebensmittelindustrie</h3><p>Hygiene und Produktsicherheit haben in der Lebensmittelproduktion höchste Priorität. Ein geschlossenes Kreislaufsystem verhindert den Kontakt der Prozessflüssigkeit mit Außenverunreinigungen. Die Kombination aus TCTP 9B und DCTP 9B deckt unterschiedliche Kapazitätsanforderungen des Werks ausgewogen ab.</p>\",\"description\":\"TCTP 9B + DCTP 9B kombiniertes Kühlsystem für Aves Yağ Speiseölproduktionswerk in Mersin.\"}','Aves Yağ Mersin — TCTP 9B + DCTP 9B Kombiniertes Kühlsystem','Aves Yağ Mersin TCTP DCTP Kühlturm — ENSOTEK','Kombiniertes TCTP 9B + DCTP 9B geschlossenes Kreislauf-Kühlsystem von ENSOTEK für Aves Yağ Speiseölwerk in Mersin.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0011-4666-8666-666600000011','33333001-0011-4333-8333-333300000011','de','TAT Tekstil — FRP-Kühlturm mit Schutzdach (Offener Kreislauf) — Gaziantep','tat-tekstil-frp-kuehlturm-schutzdach-offener-kreislauf-gaziantep','Ein FRP-Kühlturm mit Schutzdach (offener Kreislauf) wurde für das Textilproduktionswerk von TAT Tekstil in Gaziantep installiert.','{\"html\":\"<p>Ein <strong>FRP-Kühlturm mit Schutzdach (offener Kreislauf)</strong> wurde für das Produktionswerk von <strong>TAT Tekstil</strong> in <strong>Gaziantep</strong> geliefert.</p><h3>Projektdetails</h3><ul><li>Standort: Gaziantep, Türkei</li><li>Branche: Textil / Garnproduktion</li><li>Anwendung: Prozesskühlung Textilmaschinen</li></ul><h3>Kühlung in der Textilindustrie</h3><p>Textilprozesse — einschließlich Färben, Waschen und Weben — erzeugen erhebliche Wärmelasten. ENSOTEK FRP-Kühltürme bieten eine kosteneffiziente und leistungsstarke Lösung für diese anspruchsvollen industriellen Anwendungen.</p>\",\"description\":\"FRP-Kühlturm mit Schutzdach für TAT Tekstil Textilproduktionswerk in Gaziantep.\"}','TAT Tekstil Gaziantep — FRP-Kühlturm mit Schutzdach','TAT Tekstil Gaziantep Kühlturm — ENSOTEK','FRP-Kühlturm mit Schutzdach von ENSOTEK für TAT Tekstil Textilwerk in Gaziantep, Türkei, installiert.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0012-4666-8666-666600000012','33333001-0012-4333-8333-333300000012','de','Saudi-Arabien — Industrieller GFK-Kühlturm Exportprojekt','saudi-arabien-industrieller-gfk-kuehlturm-exportprojekt','ENSOTEK hat erfolgreich ein industrielles GFK-Kühlturm-Exportprojekt nach Saudi-Arabien, eine der größten Volkswirtschaften des Nahen Ostens, abgeschlossen.','{\"html\":\"<p>ENSOTEK — als größter Kühlturmhersteller der Türkei — hat erfolgreich ein industrielles <strong>GFK/FRP-Kühlturmsystem</strong> nach <strong>Saudi-Arabien</strong> im Rahmen seiner internationalen Exportaktivitäten geliefert.</p><h3>Exportprojektdetails</h3><ul><li>Land: Saudi-Arabien</li><li>Produkt: FRP / GFK Offener Kühlturm</li><li>Anwendung: Industrielle Prozesskühlung</li><li>Branche: Petrochemie / Energie / Industrie</li></ul><h3>Leistung in extremem Klima</h3><p>Die hohen Umgebungstemperaturen und das raue Klima Saudi-Arabiens erfordern besondere Konstruktionsüberlegungen bei Kühltürmen. ENSOTEK\'s GFK-Korpus bietet überlegene Beständigkeit gegen Sonnenstrahlung und extreme Hitze — für zuverlässigen Betrieb auch unter Wüstenbedingungen.</p>\",\"description\":\"Industrielles GFK-Kühlturm-Exportprojekt nach Saudi-Arabien. ENSOTEK internationale Referenz.\"}','Saudi-Arabien — GFK-Kühlturm Exportprojekt','Saudi-Arabien GFK Kühlturm Export — ENSOTEK International','ENSOTEK hat erfolgreich ein industrielles GFK-Kühlturmsystem nach Saudi-Arabien exportiert.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0013-4666-8666-666600000013','33333001-0013-4333-8333-333300000013','de','Iran — Industrieller GFK-Kühlturm Exportprojekt','iran-industrieller-gfk-kuehlturm-exportprojekt','ENSOTEK hat erfolgreich ein GFK-Kühlturm-Exportprojekt für eine Industrieanlage im Iran abgeschlossen.','{\"html\":\"<p>ENSOTEK hat im Rahmen seines regionalen Exportprogramms erfolgreich ein <strong>GFK/FRP-Kühlturmsystem</strong> an eine Industrieanlage im <strong>Iran</strong> geliefert.</p><h3>Projektdetails</h3><ul><li>Land: Iran</li><li>Produkt: FRP / GFK Offener Kühlturm</li><li>Anwendung: Industrielle Prozesskühlung</li></ul><p>ENSOTEK überträgt seine 40-jährige Erfahrung auf dem türkischen Markt auf internationale Projekte und bietet Industrieanlagen in der gesamten Region des Nahen Ostens und darüber hinaus zuverlässige Kühllösungen.</p>\",\"description\":\"GFK-Kühlturm-Exportprojekt für Industrieanlage im Iran. ENSOTEK internationale Referenz.\"}','Iran — GFK-Kühlturm Exportprojekt','Iran GFK Kühlturm Export — ENSOTEK International','ENSOTEK hat erfolgreich GFK-Kühltürme an eine Industrieanlage im Iran exportiert.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0014-4666-8666-666600000014','33333001-0014-4333-8333-333300000014','de','Tüpraş Raffinerie İzmit — Prozesskühlturmsystem','tupras-raffinerie-izmit-prozesskühlturmsystem','Ein Hochleistungs-Prozesskühlturmsystem wurde für die Tüpraş Raffinerie İzmit — Türkiens größte Ölraffinerie — geliefert.','{\"html\":\"<p>Ein <strong>Prozesskühlturmsystem</strong> wurde von ENSOTEK für die <strong>Tüpraş Raffinerie İzmit</strong> — betrieben von der Türkiye Petrol Rafinerileri A.Ş., einem der größten Industrieunternehmen der Türkei — geliefert.</p><h3>Projektdetails</h3><ul><li>Kunde: Tüpraş (Türkiye Petrol Rafinerileri A.Ş.)</li><li>Standort: İzmit, Kocaeli</li><li>Branche: Petrochemie / Ölraffinierung</li><li>Anwendung: Raffinerie-Prozesskühlung</li></ul><h3>Kühlung in der Ölraffinierung</h3><p>Raffinerieeinheiten — einschließlich Destillation, Cracken und andere Prozesse — erzeugen extreme Wärmelasten, die großvolumige Kühlsysteme erfordern. ENSOTEK-Kühltürme liefern zuverlässige, hochkapazitive Wärmeabfuhr für diese anspruchsvollen Anwendungen. Das GFK-Material bietet hervorragende Beständigkeit gegen chemische und korrosive Raffinerieumgebungen.</p>\",\"description\":\"Hochleistungs-Prozesskühlturmsystem für Tüpraş Raffinerie İzmit — Petrochemie-Referenz.\"}','Tüpraş Raffinerie İzmit — Prozesskühlturmsystem','Tüpraş İzmit Raffinerie Kühlturm — ENSOTEK','Hochleistungs-Prozesskühlturmsystem von ENSOTEK für Tüpraş İzmit Raffinerie, Türkiens größte Ölraffinerie.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669'),('66666001-0015-4666-8666-666600000015','33333001-0015-4333-8333-333300000015','de','TOFAS Automobilwerk Bursa — GFK-Kühlturm mit Schutzdach (Offener Kreislauf)','tofas-automobilwerk-bursa-gfk-kuehlturm-schutzdach-offener-kreislauf','Ein FRP-Kühlturmsystem mit Schutzdach wurde für das Automobilproduktionswerk von TOFAS in Bursa in Betrieb genommen.','{\"html\":\"<p>Ein <strong>FRP-Kühlturm mit Schutzdach (offener Kreislauf)</strong> wurde für das großangelegte Automobilproduktionswerk von <strong>TOFAS</strong> (Türk Otomobil Fabrikası A.Ş.) in <strong>Bursa</strong> geliefert.</p><h3>Projektdetails</h3><ul><li>Kunde: TOFAS (Türk Otomobil Fabrikası A.Ş.)</li><li>Standort: Bursa, Türkei</li><li>Branche: Automobil / Fahrzeugproduktion</li><li>Anwendung: Lackierstraßen, Formkühlung und Prozesskühlung</li></ul><h3>Kühlung in der Automobilfertigung</h3><p>Automobilwerke — einschließlich Lackierstraßen, Schweißstationen und Formkühlsysteme — benötigen hohe Kühlkapazitäten. ENSOTEK\'s FRP-Kühltürme bieten hohe Durchflusskapazität, lange Lebensdauer und niedrige Wartungskosten.</p>\",\"description\":\"FRP-Kühlturm mit Schutzdach für TOFAS Automobilproduktionswerk in Bursa.\"}','TOFAS Automobilwerk Bursa — FRP-Kühlturm mit Schutzdach','TOFAS Bursa Automobilwerk Kühlturm — ENSOTEK','FRP-Kühlturm mit Schutzdach von ENSOTEK für TOFAS Automobilproduktionswerk in Bursa, Türkei, in Betrieb genommen.','2026-03-23 04:11:30.669','2026-03-23 04:11:30.669');
