/*!40000 ALTER TABLE `review_i18n` DISABLE KEYS */;
INSERT INTO `review_i18n` VALUES ('44440001-4444-4444-8444-444444441001','44440001-4444-4444-8444-444444440001','tr','Misyon metni çok net ve anlaşılır','Ensotek\'in misyon açıklaması, sektöre bakışını ve müşteri odaklı yaklaşımını çok net şekilde ortaya koyuyor.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440001-4444-4444-8444-444444441002','44440001-4444-4444-8444-444444440001','en','Strong customer-oriented mission','I really like how Ensotek puts customer satisfaction and efficiency at the center of its mission.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440001-4444-4444-8444-444444441003','44440001-4444-4444-8444-444444440001','de','Klare und kundenorientierte Mission','Die Mission ist verständlich formuliert und zeigt den Fokus auf Effizienz und Kundenzufriedenheit.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440003-4444-4444-8444-444444443001','44440003-4444-4444-8444-444444440003','tr','40 yıllık deneyimi hissettiriyor','Hakkımızda sayfasındaki bilgiler, firmanın sektörde ne kadar köklü ve tecrübeli olduğunu çok iyi anlatıyor.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440003-4444-4444-8444-444444443002','44440003-4444-4444-8444-444444440003','en','Impressive background','The about page gives a very clear picture of Ensotek\'s long-term experience and strong reference projects.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440003-4444-4444-8444-444444443003','44440003-4444-4444-8444-444444440003','de','Sehr überzeugender Unternehmenshintergrund','Die „Über uns“-Seite vermittelt einen klaren Eindruck von Ensoteks Erfahrung und den starken Referenzprojekten.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440005-4444-4444-8444-444444445001','44440005-4444-4444-8444-444444440005','tr','Bakım rehberi çok faydalı','Periyodik bakım yazısı, sahadaki ekibimiz için kontrol listesi gibi kullanabileceğimiz pratik bilgiler içeriyor.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440005-4444-4444-8444-444444445002','44440005-4444-4444-8444-444444440005','en','Very practical maintenance guide','The periodic maintenance article provides actionable tips that can be used as a checklist by field teams.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440005-4444-4444-8444-444444445003','44440005-4444-4444-8444-444444440005','de','Sehr hilfreicher Wartungsleitfaden','Der Artikel zur regelmäßigen Wartung enthält praxisnahe Hinweise, die sich als Checkliste für Serviceteams nutzen lassen.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440011-4444-4444-8444-444444440111','44440011-4444-4444-8444-444444440011','tr','Soğutma kulesi seçimi için çok iyi bir özet','Soğutma kulesi sayfasında kapasiteler, çalışma prensibi ve seçim kriterleri sade ve teknik olarak doğru anlatılmış. Proje başlangıcında doğru karar vermemize yardımcı oldu.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440011-4444-4444-8444-444444440112','44440011-4444-4444-8444-444444440011','en','Excellent overview for selecting a cooling tower','The page explains capacity, operating principles and selection criteria in a clear and technically accurate way. It helped us make the right call at the start of the project.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440011-4444-4444-8444-444444440113','44440011-4444-4444-8444-444444440011','de','Sehr guter Überblick zur Auswahl von Kühltürmen','Die Seite erläutert Kapazität, Funktionsprinzip und Auswahlkriterien klar und technisch korrekt. Das hat uns bei der Projektentscheidung deutlich geholfen.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440012-4444-4444-8444-444444440121','44440012-4444-4444-8444-444444440012','tr','Açık/kapalı devre farkı netleşti','Açık devre, kapalı devre ve hibrit çözümlerin avantaj/dezavantajları iyi karşılaştırılmış. Özellikle su kalitesi ve bakım ihtiyacı açısından doğru çerçeve sunuyor.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440012-4444-4444-8444-444444440122','44440012-4444-4444-8444-444444440012','en','Clear comparison of open vs. closed circuit','The pros/cons of open circuit, closed circuit and hybrid solutions are well structured. It sets the right expectations about water quality and maintenance requirements.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440012-4444-4444-8444-444444440123','44440012-4444-4444-8444-444444440012','de','Guter Vergleich: offener vs. geschlossener Kreislauf','Vor- und Nachteile von offenen, geschlossenen und hybriden Systemen sind sauber gegenübergestellt – besonders im Hinblick auf Wasserqualität und Wartungsaufwand.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440013-4444-4444-8444-444444440131','44440013-4444-4444-8444-444444440013','tr','Bakım ve hijyen adımları pratik','Periyodik bakım adımları (dolgu kontrolü, fan-kayış ayarı, su şartlandırma, drift eliminatör temizliği) sahada uygulanabilir şekilde yazılmış. Hijyen ve verim için önemli.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440013-4444-4444-8444-444444440132','44440013-4444-4444-8444-444444440013','en','Practical maintenance and hygiene steps','Maintenance steps (fill inspection, fan/belt alignment, water treatment, drift eliminator cleaning) are described in an actionable way. Great for hygiene and efficiency.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440013-4444-4444-8444-444444440133','44440013-4444-4444-8444-444444440013','de','Praxisnahe Wartungs- und Hygieneschritte','Wartungspunkte (Füllkörper, Ventilator/Riemen, Wasseraufbereitung, Drift-Eliminator) sind sehr praxisnah beschrieben – wichtig für Hygiene und Effizienz.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440014-4444-4444-8444-444444440141','44440014-4444-4444-8444-444444440014','tr','Referanslar güven veriyor','Soğutma kuleleri referans projeleri sektör çeşitliliği açısından güçlü. Teklif sürecinde teknik ekip için ikna edici oldu.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440014-4444-4444-8444-444444440142','44440014-4444-4444-8444-444444440014','en','References inspire confidence','The cooling tower reference projects show strong sector coverage. It was convincing for our technical team during the quotation process.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440014-4444-4444-8444-444444440143','44440014-4444-4444-8444-444444440014','de','Referenzen schaffen Vertrauen','Die Referenzprojekte im Bereich Kühltürme zeigen eine starke Branchenabdeckung. Das war im Angebotsprozess sehr überzeugend.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440015-4444-4444-8444-444444440151','44440015-4444-4444-8444-444444440015','tr','Ses seviyesi için doğru yaklaşım','Ses seviyesi ve titreşim konularında doğru mühendislik yaklaşımı anlatılmış. Yerleşim, fan seçimi ve izolasyon gibi detaylar karar sürecini kolaylaştırdı.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440015-4444-4444-8444-444444440152','44440015-4444-4444-8444-444444440015','en','Good engineering approach for noise control','The page addresses noise and vibration with the right engineering perspective. Layout, fan choice and isolation details helped streamline decisions.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440015-4444-4444-8444-444444440153','44440015-4444-4444-8444-444444440015','de','Guter Ansatz für Schall- und Vibrationskontrolle','Schall und Vibration werden mit dem richtigen Engineering-Fokus erklärt. Aufstellung, Ventilatorwahl und Entkopplung waren sehr hilfreich.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440016-4444-4444-8444-444444440161','44440016-4444-4444-8444-444444440016','tr','Su tüketimi ve şartlandırma bilgisi yerinde','Buharlaşma kaybı, sürüklenme (drift) ve blöf (blowdown) gibi konuların açıklanması faydalı. Su şartlandırma önerileri net ve uygulanabilir.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440016-4444-4444-8444-444444440162','44440016-4444-4444-8444-444444440016','en','Solid information on water use and treatment','Explanations about evaporation loss, drift and blowdown are helpful. Water treatment guidance is clear and practical.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020'),('44440016-4444-4444-8444-444444440163','44440016-4444-4444-8444-444444440016','de','Gute Informationen zu Wasserverbrauch und Aufbereitung','Erläuterungen zu Verdunstung, Drift und Blowdown sind sehr nützlich. Empfehlungen zur Wasseraufbereitung sind klar und praxisnah.',NULL,'2026-03-23 04:11:29.020','2026-03-23 04:11:29.020');
/*!40000 ALTER TABLE `review_i18n` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `reviews`
