-4111-8111-aaaaaaaa8001','bbbb8006-1111-4111-8111-bbbbbbbb8006',1,1,40,NULL,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1767320750/services/cover/automation_and_scada.png',NULL,NULL,'Monitoring / control / reporting','2–8 weeks (scope dependent)','Periodic calibration & verification recommended','All seasons',NULL,'Flow, temperature, conductivity, level, vibration switch, energy monitoring, alarms, remote access','2026-03-23 04:11:29.189','2026-03-23 04:11:29.189'),('90000005-1111-4111-8111-900000000005','engineering_support','aaaa8001-1111-4111-8111-aaaaaaaa8001','bbbb8006-1111-4111-8111-bbbbbbbb8006',1,1,50,NULL,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1767320817/services/cover/engineering_support.png',NULL,NULL,'Design / consulting / optimization','2–8 weeks (scope dependent)','Optional periodic review + reporting','All seasons',NULL,'Heat load analysis, sizing, hydraulic balancing, performance assessment, documentation, technical training','2026-03-23 04:11:29.193','2026-03-23 04:11:29.193'),('90000006-1111-4111-8111-900000000006','site_survey_engineering','aaaa8001-1111-4111-8111-aaaaaaaa8001','bbbb8006-1111-4111-8111-bbbbbbbb8006',1,1,60,NULL,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1767320879/services/cover/site_survey_and_engineering.png',NULL,NULL,'On-site survey / mechanical layout / selection','1 day – 3 weeks (survey + design)','Optional: integration plan with maintenance','All seasons',NULL,'Site survey, process conditions, selection & sizing, piping concept, access platforms, safety checklist','2026-03-23 04:11:29.197','2026-03-23 04:11:29.197'),('90000007-1111-4111-8111-900000000007','performance_optimization','aaaa8001-1111-4111-8111-aaaaaaaa8001','bbbb8006-1111-4111-8111-bbbbbbbb8006',1,1,70,NULL,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1767321149/services/cover/performance_optimization.png',NULL,NULL,'Measurement / reporting / optimization','1 day – 4 weeks (measure + actions)','Best results with periodic monitoring','All seasons',NULL,'Approach temperature, fan efficiency, distribution quality, drift loss, water chemistry baseline, reporting','2026-03-23 04:11:29.202','2026-03-23 04:11:29.202'),('90000008-1111-4111-8111-900000000008','commissioning_startup','aaaa8001-1111-4111-8111-aaaaaaaa8001','bbbb8006-1111-4111-8111-bbbbbbbb8006',1,1,80,NULL,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1767321196/services/cover/commissioning_and_startup.png',NULL,NULL,'Installation coordination / commissioning / training','1 day – 2 weeks (project dependent)','Handover checklist & initial maintenance plan included','All seasons',NULL,'Pre-start checks, test runs, vibration checks, water distribution tests, handover documentation, operator training','2026-03-23 04:11:29.206','2026-03-23 04:11:29.206'),('90000009-1111-4111-8111-900000000009','emergency_response','aaaa8001-1111-4111-8111-aaaaaaaa8001','bbbb8002-1111-4111-8111-bbbbbbbb8002',1,1,90,NULL,'https://res.cloudinary.com/dbozv7wqd/image/upload/v1767321228/services/cover/emergency_response.png',NULL,NULL,'Urgent troubleshooting / safe restart','Same day – 7 days (depending on fault)','Follow-up maintenance action plan recommended','All seasons',NULL,'Rapid diagnostics, part replacement, safe restart, temporary bypass planning, incident report','2026-03-23 04:11:29.211','2026-03-23 04:11:29.211');
