INSERT INTO `slider_i18n` VALUES (1,1,'tr','xxxxxxxxxxxxxEndüstriyel Su Soğutma Kulelerinde Uzman Çözüm Ortağınız','endustriyel-su-sogutma-kulelerinde-uzman-cozum-ortaginiz','<h2>xxxxxxxxxxxEndüstriyel Su Soğutma Kuleleri</h2><p>Enerji santralleri, endüstriyel tesisler ve ticari binalar için yüksek verimli su soğutma kulesi çözümleri sunuyoruz. Ensotek olarak, müşterilerimizin soğutma ihtiyaçlarını karşılamak için özel olarak tasarlanmış su soğutma kuleleri sunuyoruz.</p><h3>Üstün Verimlilik</h3>','Endüstriyel su soğutma kulesi çözümleri','Teklif Al','/offer'),(2,2,'tr','Açık ve Kapalı Devre Su Soğutma Kuleleri','acik-ve-kapali-devre-su-sogutma-kuleleri','FRP, galvanizli çelik ve betonarme gövdeli su soğutma kuleleri ile prosesinize en uygun çözümü tasarlıyoruz.','Açık / kapalı devre su soğutma kuleleri','Çözümleri İncele','/solutions/water-cooling-towers'),(3,3,'tr','Keşif, Projelendirme ve Anahtar Teslim Uygulama','kesif-projelendirme-ve-anahtar-teslim-uygulama','Saha keşfi, ısı yükü hesapları, mekanik tasarım, montaj koordinasyonu ve devreye alma süreçlerini Ensotek mühendisliği ile uçtan uca yönetiyoruz.','Su soğutma kulesi keşif ve projelendirme','Hizmeti İncele','/service/site-survey-engineering'),(4,4,'tr','Periyodik Bakım, Onarım ve Revizyon','periyodik-bakim-onarim-ve-revizyon','Mevcut su soğutma kulelerinizde nozül, dolgu, fan ve mekanik aksam yenileme ile kapasite ve verimlilik iyileştirmeleri sağlıyoruz.','Su soğutma kulesi bakım ve revizyon hizmetleri','Bakım Planla','/service/maintenance-repair'),(5,5,'tr','Otomasyon, SCADA ve Uzaktan İzleme','otomasyon-scada-ve-uzaktan-izleme','Su soğutma kulelerinizi enerji tüketimi, debi, sıcaklık ve arıza durumlarına göre gerçek zamanlı izleyebileceğiniz otomasyon altyapısı kuruyoruz.','Su soğutma kulesi otomasyon ve SCADA çözümleri','Hizmeti İncele','/service/automation-scada'),(6,6,'tr','Yedek Parçalar ve Kritik Bileşen Tedariği','yedek-parcalar-ve-kritik-bilesen-tedarigi','Nozül, dolgu, fan kanadı, motor, redüktör, drift eliminator ve mekanik aksamlar için hızlı tedarik ve doğru parça eşleştirme desteği sunuyoruz.','Soğutma kulesi yedek parça ve bileşen tedariği','Hizmeti İncele','/service/spare-parts-components'),(7,7,'tr','Modernizasyon ve Verimlilik Odaklı Retrofit','modernizasyon-ve-verimlilik-odakli-retrofit','Mevcut kulelerinizi daha düşük enerji tüketimi ve daha yüksek performans için yeniliyoruz: dolgu/nozül optimizasyonu, fan grubu yükseltme ve hidrolik iyileştirmeler.','Soğutma kulesi modernizasyon ve retrofit','Hizmeti İncele','/service/modernization-retrofit'),(8,8,'tr','Proje Danışmanlığı ve Mühendislik Desteği','proje-danismanligi-ve-muhendislik-destegi','Isı yükü analizi, seçim/boyutlandırma, malzeme seçimi ve saha koşullarına göre uçtan uca mühendislik desteği sağlıyoruz.','Soğutma kulesi mühendislik danışmanlığı','Hizmeti İncele','/service/engineering-support'),(9,9,'tr','Otomasyon ve Uzaktan İzleme Altyapısı','otomasyon-ve-uzaktan-izleme-altyapisi','Debi, sıcaklık, iletkenlik, seviye ve enerji tüketimi gibi kritik parametreleri izleyerek arızaları erken yakalayan izleme altyapıları kuruyoruz.','Soğutma kulesi otomasyon ve uzaktan izleme','Hizmeti İncele','/service/automation-scada'),(10,10,'tr','Performans Optimizasyonu ve Enerji Verimliliği','performans-optimizasyonu-ve-enerji-verimliligi','Yerinde ölçümler ve raporlama ile yaklaşım sıcaklığı, kapasite, fan verimi ve su kimyası parametrelerini iyileştirerek enerji maliyetlerini düşürüyoruz.','Soğutma kulesi performans optimizasyonu','Hizmeti İncele','/service/performance-optimization'),(11,11,'tr','Kurulum & Devreye Alma','kurulum-ve-devreye-alma','Montaj koordinasyonu, kontrol listeleri, testler ve güvenli ilk çalıştırma adımları ile sistemi devreye alıyor; operatör eğitimini tamamlıyoruz.','Soğutma kulesi kurulum ve devreye alma','Hizmeti İncele','/service/commissioning-startup'),(12,12,'tr','Acil Servis ve Arıza Müdahalesi','acil-servis-ve-ariza-mudahalesi','Kritik duruşlara karşı hızlı müdahale, parça değişimi, devreye alma ve güvenli yeniden çalıştırma süreçlerinde saha ekibimizle yanınızdayız.','Soğutma kulesi acil servis ve arıza müdahalesi','Acil Destek','/service/emergency-response'),(13,1,'en','Your Expert Partner in Industrial Cooling Tower Solutions','your-expert-partner-in-industrial-cooling-tower-solutions','We deliver high-efficiency cooling tower solutions for power plants, industrial facilities, and commercial buildings.','Industrial cooling tower solutions','Get a Quote','/offer'),(14,2,'en','Open & Closed Circuit Cooling Towers','open-and-closed-circuit-cooling-towers','We design the best-fit solution for your process with FRP, galvanized steel, and reinforced concrete cooling towers.','Open / closed circuit cooling towers','Explore Solutions','/solutions/water-cooling-towers'),(15,3,'en','Site Survey, Engineering & Turnkey Implementation','site-survey-engineering-and-turnkey-implementation','From site survey and heat load calculations to mechanical design, installation coordination, and commissioning—Ensotek manages the full lifecycle end-to-end.','Cooling tower site survey and engineering','View Service','/services/site-survey-engineering'),(16,4,'en','Periodic Maintenance, Repair & Overhaul','periodic-maintenance-repair-and-overhaul','We improve capacity and efficiency through nozzle/fill replacement, fan upgrades, and mechanical refurbishment for your existing cooling towers.','Cooling tower maintenance and overhaul services','Plan Maintenance','/services/maintenance-repair'),(17,5,'en','Automation, SCADA & Remote Monitoring','automation-scada-and-remote-monitoring','We implement automation infrastructure to monitor energy consumption, flow, temperature, and fault conditions in real time.','Cooling tower automation and SCADA solutions','View Service','/services/automation-scada'),(18,6,'en','Spare Parts & Critical Components Supply','spare-parts-and-critical-components-supply','Fast sourcing and accurate part matching for nozzles, fill media, fan blades, motors, gearboxes, drift eliminators, and mechanical components.','Cooling tower spare parts and components supply','View Service','/services/spare-parts-components'),(19,7,'en','Modernization & Efficiency-Focused Retrofit','modernization-and-efficiency-focused-retrofit','Upgrade existing towers for lower energy use and higher performance: fill/nozzle optimization, fan group upgrades, and hydraulic improvements.','Cooling tower modernization and retrofit','View Service','/services/modernization-retrofit'),(20,8,'en','Project Consulting & Engineering Support','project-consulting-and-engineering-support','End-to-end engineering support based on heat load analysis, selection/sizing, material choice, and site conditions.','Cooling tower engineering consulting','View Service','/services/engineering-support'),(21,9,'en','Automation & Remote Monitoring Infrastructure','automation-and-remote-monitoring-infrastructure','Build monitoring systems that detect issues early by tracking critical parameters such as flow, temperature, conductivity, level, and energy consumption.','Cooling tower automation and remote monitoring','View Service','/services/automation-scada'),(22,10,'en','Performance Optimization & Energy Efficiency','performance-optimization-and-energy-efficiency','Reduce energy costs by improving approach temperature, capacity, fan efficiency, and water chemistry through on-site measurements and reporting.','Cooling tower performance optimization','View Service','/services/performance-optimization'),(23,11,'en','Installation & Commissioning','installation-and-commissioning','We deliver commissioning with installation coordination, checklists, testing, safe startup procedures, and operator training.','Cooling tower installation and commissioning','View Service','/services/commissioning-startup'),(24,12,'en','Emergency Service & Breakdown Response','emergency-service-and-breakdown-response','Rapid response for critical shutdowns, part replacement, commissioning support, and safe restart with our field team.','Cooling tower emergency service and breakdown response','Emergency Support','/contact'),(25,1,'de','Ihr Partner für industrielle Kühlturmlösungen','ihr-partner-fuer-industrielle-kuehlturmloesungen','Wir bieten hocheffiziente Kühlturmlösungen für Kraftwerke, Industrieanlagen und Gewerbeimmobilien.','Industrielle Kühlturmlösungen','Angebot anfordern','/offer'),(26,2,'de','Offene & geschlossene Kreislauf-Kühltürme','offene-und-geschlossene-kreislauf-kuehltuerme','Wir konzipieren die passende Lösung für Ihren Prozess mit Kühltürmen aus GFK, verzinktem Stahl und Stahlbeton.','Offene / geschlossene Kreislauf-Kühltürme','Lösungen ansehen','/solutions/water-cooling-towers'),(27,3,'de','Standortanalyse, Engineering & schlüsselfertige Umsetzung','standortanalyse-engineering-und-schluesselfertige-umsetzung','Von der Standortanalyse und Wärmeleistungsberechnung über die mechanische Auslegung bis hin zur Montagekoordination und Inbetriebnahme – Ensotek übernimmt alles aus einer Hand.','Kühlturm Standortanalyse und Engineering','Service ansehen','/services/site-survey-engineering'),(28,4,'de','Regelmäßige Wartung, Reparatur & Revision','regelmaessige-wartung-reparatur-und-revision','Wir steigern Kapazität und Effizienz durch Düsen-/Füllkörpertausch, Ventilator-Upgrades und mechanische Überholung Ihrer bestehenden Kühltürme.','Kühlturm Wartung und Revision','Wartung planen','/services/maintenance-repair'),(29,5,'de','Automation, SCADA & Fernüberwachung','automation-scada-und-fernueberwachung','Wir implementieren Automationslösungen zur Echtzeitüberwachung von Energieverbrauch, Durchfluss, Temperatur und Störungen.','Kühlturm Automation und SCADA','Service ansehen','/services/automation-scada'),(30,6,'de','Ersatzteile & kritische Komponenten','ersatzteile-und-kritische-komponenten','Schnelle Beschaffung und passgenaue Zuordnung für Düsen, Füllkörper, Ventilatorflügel, Motoren, Getriebe, Driftabscheider und mechanische Komponenten.','Kühlturm Ersatzteile und Komponenten','Service ansehen','/services/spare-parts-components'),(31,7,'de','Modernisierung & effizienzorientiertes Retrofit','modernisierung-und-effizienzorientiertes-retrofit','Wir modernisieren bestehende Kühltürme für geringeren Energieverbrauch und höhere Leistung: Füllkörper-/Düsenoptimierung, Ventilator-Upgrades und hydraulische Verbesserungen.','Kühlturm Modernisierung und Retrofit','Service ansehen','/services/modernization-retrofit'),(32,8,'de','Projektberatung & Engineering-Support','projektberatung-und-engineering-support','Umfassende Engineering-Unterstützung basierend auf Wärmeleistungsanalyse, Auswahl/Dimensionierung, Materialwahl und Standortbedingungen.','Kühlturm Engineering-Beratung','Service ansehen','/services/engineering-support'),(33,9,'de','Automations- & Fernüberwachungsinfrastruktur','automations-und-fernueberwachungsinfrastruktur','Wir bauen Monitoring-Systeme, die Störungen früh erkennen – durch Überwachung von Durchfluss, Temperatur, Leitfähigkeit, Füllstand und Energieverbrauch.','Kühlturm Automation und Fernüberwachung','Service ansehen','/services/automation-scada'),(34,10,'de','Performance-Optimierung & Energieeffizienz','performance-optimierung-und-energieeffizienz','Durch Vor-Ort-Messungen und Reportings verbessern wir Annäherungstemperatur, Kapazität, Ventilatoreffizienz und Wasserchemie – und senken Ihre Energiekosten.','Kühlturm Performance-Optimierung','Service ansehen','/services/performance-optimization'),(35,11,'de','Montage & Inbetriebnahme','montage-und-inbetriebnahme','Wir realisieren die Inbetriebnahme inklusive Montagekoordination, Checklisten, Tests, sicherem Start-up und Bedienerschulung.','Kühlturm Montage und Inbetriebnahme','Service ansehen','/services/commissioning-startup'),(36,12,'de','Notdienst & Störungsbehebung','notdienst-und-stoerungsbehebung','Schnelle Hilfe bei kritischen Stillständen, Teiletausch, Inbetriebnahme-Unterstützung und sicherem Wiederanlauf durch unser Außendienstteam.','Kühlturm Notdienst und Störungsbehebung','Soforthilfe','/contact');
